(882,	'_site_transient_feed_0d2db5fea5a8633b56992c916819b198',	'a:6:{s:5:\"child\";a:1:{s:0:\"\";a:1:{s:3:\"rss\";a:1:{i:0;a:6:{s:4:\"data\";s:3:\"\n\n\n\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:7:\"version\";s:3:\"2.0\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:1:{s:7:\"channel\";a:1:{i:0;a:6:{s:4:\"data\";s:52:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\n \n	\n		\n		\n		\n		\n		\n		\n		\n		\n		\n	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:8:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"Blog – WordPress.org Français\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://fr.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:13:\"lastBuildDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jun 2026 12:17:47 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"language\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"fr-FR\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"generator\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"https://wordpress.org/?v=7.1-alpha-62624\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"image\";a:1:{i:0;a:6:{s:4:\"data\";s:11:\"\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:5:{s:3:\"url\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"https://s.w.org/favicon.ico?2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"Blog – WordPress.org Français\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://fr.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"WordPress 7.0 « Armstrong »\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://fr.wordpress.org/2026/06/10/wordpress-7-0-armstrong/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jun 2026 12:15:39 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Nouvelles versions de WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://fr.wordpress.org/?p=3453\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:395:\"Chaque nouvelle version de WordPress rend hommage à un artiste qui a marqué de manière indélébile l’univers de la musique. Découvrez WordPress 7.0 « Armstrong », nommé en l’honneur du célèbre musicien de jazz Louis Armstrong. Considéré comme le « premier grand soliste de jazz », Louis Armstrong a créé des formations qui mettaient en valeur son immense talent [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Jenny Dupuy\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:82195:\"<figure class=\"alignfull wp-block-post-featured-image\"><img fetchpriority=\"high\" decoding=\"async\" width=\"2048\" height=\"1365\" src=\"https://fr.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0.png\" class=\"attachment-post-thumbnail size-post-thumbnail wp-post-image\" alt=\"\" style=\"object-fit:cover;\" srcset=\"https://fr.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0.png 2048w, https://fr.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-300x200.png 300w, https://fr.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-1024x683.png 1024w, https://fr.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-768x512.png 768w, https://fr.wordpress.org/files/2026/05/Release-Edition-Main-Image-7.0-1536x1024.png 1536w\" sizes=\"(max-width: 2048px) 100vw, 2048px\" /></figure>\n\n\n<p class=\"wp-block-paragraph\">Chaque nouvelle version de WordPress rend hommage à un artiste qui a marqué de manière indélébile l’univers de la musique. Découvrez WordPress 7.0 « Armstrong », nommé en l’honneur du célèbre musicien de jazz Louis Armstrong.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Considéré comme le « premier grand soliste de jazz », Louis Armstrong a créé des formations qui mettaient en valeur son immense talent de trompettiste et, ce faisant, a transformé le jazz, le faisant passer d’un art orchestral à un art soliste. Ce maître de la trompette a également impressionné le monde entier par son style vocal caractéristique, en introduisant l’improvisation dans le jazz, en influençant tous les artistes avec lesquels il a travaillé et en modifiant à jamais le paysage musical.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Louis Armstrong a insufflé sa touche personnelle au monde du jazz. C’est en son honneur que WordPress 7.0 est baptisé « Armstrong ».</p>\n\n\n\n<h2 class=\"wp-block-heading\">Bienvenue sur WordPress 7.0 !</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 marque le début d’une nouvelle ère et jette les bases de l’intégration de l’IA dans l&rsquo;ensemble de l’expérience WordPress. Avec son tableau de bord moderne et plus intuitif, la version 7.0 propose des outils de personnalisation et de développement améliorés qui stimulent la créativité et ouvrent la voie à un potentiel infini.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Que vous soyez créateur, chef d’entreprise ou développeur, WordPress 7.0 vous permet de créer à votre manière, en toute liberté.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://fr.wordpress.org/download/\">Télécharger WordPress 7.0 en français</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Quelles nouveautés dans cette version majeure ?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Découvrez les nouvelles fonctionnalités d’IA directement sur votre site web, le tout géré depuis une plateforme centralisée. Naviguez en toute fluidité dans le nouveau thème d’administration épuré, disponible sur l’ensemble du tableau de bord. Stimulez votre créativité grâce à de nouveaux blocs et outils de conception, et profitez d’une boîte à outils de développement complète qui vous offre plus de contrôle que jamais, vous permettant ainsi de publier du contenu à votre guise.</p>\n\n\n\n<h3 class=\"wp-block-heading\">L’IA intégrée dans WordPress</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Grâce à l’intégration de l’IA au sein de WordPress, les possibilités sont devenues infinies. Un nouveau client IA intégré au cœur du système permet à WordPress de communiquer avec des modèles d’IA générative, tandis que les connexions sont facilement gérées depuis un hub unique dans le tableau de bord. Associé à l’API « Abilities », ce client IA forme un duo de choc qui apporte de nouvelles fonctionnalités, l’automatisation des flux de travail et des outils de création à votre site web. Installez la nouvelle estension IA pour élargir encore davantage vos options : générez et modifiez des images, créez des titres ou des extraits, ou même suggérez des textes alternatifs pour vos images.</p>\n\n\n\n<p class=\"wp-block-paragraph\">La version 7.0 inclut également un nouveau package « Client-Side Abilities » : un équivalent Javascript de l’API Abilities, doté d’une interface d’utilisation intégrée et d’une palette de commandes qui offre de nombreux outils orientés IA.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/05/image-13.png\"><img decoding=\"async\" width=\"1360\" height=\"840\" src=\"https://fr.wordpress.org/files/2026/05/image-13.png\" alt=\"\" class=\"wp-image-3457\" srcset=\"https://fr.wordpress.org/files/2026/05/image-13.png 1360w, https://fr.wordpress.org/files/2026/05/image-13-300x185.png 300w, https://fr.wordpress.org/files/2026/05/image-13-767x474.png 767w, https://fr.wordpress.org/files/2026/05/image-13-1024x632.png 1024w\" sizes=\"(max-width: 1360px) 100vw, 1360px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Gérez toutes vos connexions externes depuis un hub central sur l’écran Connecteurs. Lancez-vous facilement grâce à trois pré-réglages ou ajoutez vos propres connexions. Authentifiez-vous et commencez à utiliser les fonctionnalités d’IA en quelques clics seulement.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-12.png\"><img decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-12.png\" alt=\"\" class=\"wp-image-3476\" srcset=\"https://fr.wordpress.org/files/2026/06/image-12.png 1024w, https://fr.wordpress.org/files/2026/06/image-12-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-12-768x474.png 768w\" sizes=\"(max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Cette version de WordPress intégrant l’IA offre donc un potentiel infini, prêt à être exploré.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Un tableau de bord modernisé</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Optimisez votre expérience d’administration.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">La version 7.0 propose un tableau de bord entièrement repensé, doté d’une nouvelle palette de couleurs élégante et moderne, ainsi que d’une mise en page épurée.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Grâce à des transitions fluides qui s’enchaînent sans à-coups lorsque vous passez d’un écran à l’autre, vous aurez l’impression de naviguer sans effort à travers le tableau de bord.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Un simple clic sur le nouveau raccourci de la palette de commandes, représenté par l’icône ⌘K ou Ctrl+K dans la barre d’administration supérieure, vous permet d’accéder à vos outils préférés depuis n’importe quel endroit du tableau de bord.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-11.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-11.png\" alt=\"\" class=\"wp-image-3478\" srcset=\"https://fr.wordpress.org/files/2026/06/image-11.png 1024w, https://fr.wordpress.org/files/2026/06/image-11-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-11-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Découvrez toutes les polices en un seul endroit, quel que soit le thème. Installez, téléchargez et gérez votre collection de polices depuis la nouvelle page dédiée à la gestion des polices, compatible avec tous les types de thèmes : « basé sur des blocs », « hybride » ou « classique ».</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-10.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-10.png\" alt=\"\" class=\"wp-image-3480\" srcset=\"https://fr.wordpress.org/files/2026/06/image-10.png 1024w, https://fr.wordpress.org/files/2026/06/image-10-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-10-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Parcourez visuellement les différentes versions pour voir d’un seul coup d’œil ce qui a changé, grâce à des repères qui facilitent la prise de décision. Sélectionnez facilement la version souhaitée et restaurez-la instantanément.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-9.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-9.png\" alt=\"\" class=\"wp-image-3482\" srcset=\"https://fr.wordpress.org/files/2026/06/image-9.png 1024w, https://fr.wordpress.org/files/2026/06/image-9-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-9-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Concevez, créez, personnalisez</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Une façon plus simple de créer.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Laissez WordPress vous inspirer grâce à de nouveaux blocs, des supports de blocs et des outils de conception qui apportent une agilité visuelle et un contrôle précis, tout en veillant à ce que chaque élément de votre site web reste fidèle à votre image de marque, avec une touche de fraîcheur.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Mettez vos idées en valeur dans un diaporama en mode « <bdo lang=\"en\" dir=\"ltr\">lightbox</bdo> » grâce au nouveau bloc Galerie, et peaufinez votre balisage avec le nouveau bloc Titre. Offrez une navigation claire sur votre site grâce au nouveau bloc Fil d&rsquo;Ariane, et ajoutez plus de détails à vos designs avec le nouveau bloc Icône.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-8.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-8.png\" alt=\"\" class=\"wp-image-3484\" srcset=\"https://fr.wordpress.org/files/2026/06/image-8.png 1024w, https://fr.wordpress.org/files/2026/06/image-8-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-8-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Le contrôle de la « responsivité » a été amélioré dans la version 7.0, ce qui rend votre site plus convivial. Masquez et affichez des blocs en fonction de l’appareil (ordinateur, tablette, mobile), sans affecter les autres fenêtres d’affichage.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-7.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-7.png\" alt=\"\" class=\"wp-image-3486\" srcset=\"https://fr.wordpress.org/files/2026/06/image-7.png 1024w, https://fr.wordpress.org/files/2026/06/image-7-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-7-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Concevez et créez votre superposition de menu à l’aide de blocs et de compositions, entièrement personnalisables selon le style que vous souhaitez présenter à vos visiteurs. Ajoutez des colonnes, personnalisez la typographie ou intégrez votre propre bouton de fermeture dans la superposition de menu. Commencez avec un modèle ou créez votre propre superposition de menu à partir de zéro.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-6-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-6-1.png\" alt=\"\" class=\"wp-image-3490\" srcset=\"https://fr.wordpress.org/files/2026/06/image-6-1.png 1024w, https://fr.wordpress.org/files/2026/06/image-6-1-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-6-1-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Affinez la conception et la mise en page de vos pages grâce à des compositions qui fonctionnent comme un tout, mais qui peuvent être décomposées pour un contrôle plus précis. Insérez votre composition, permutez les éléments et personnalisez-la en toute simplicité.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-5.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-5.png\" alt=\"\" class=\"wp-image-3492\" srcset=\"https://fr.wordpress.org/files/2026/06/image-5.png 1024w, https://fr.wordpress.org/files/2026/06/image-5-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-5-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Personnalisez chaque détail de votre contenu à l’aide de CSS personnalisés au niveau des blocs, directement dans votre publication.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://fr.wordpress.org/files/2026/06/image-4.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"632\" src=\"https://fr.wordpress.org/files/2026/06/image-4.png\" alt=\"\" class=\"wp-image-3494\" srcset=\"https://fr.wordpress.org/files/2026/06/image-4.png 1024w, https://fr.wordpress.org/files/2026/06/image-4-300x185.png 300w, https://fr.wordpress.org/files/2026/06/image-4-768x474.png 768w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Boîte à outils de développement</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Des outils avancés pour créer à votre façon.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 vous permet de créer plus rapidement, plus efficacement, plus solidement et plus facilement grâce à un ensemble complet d’API étendues et de fonctionnalités améliorées.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Créez des blocs et des compositions au niveau du serveur en utilisant uniquement PHP, avec enregistrement automatique via l’API des blocs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Découvrez un éditeur de site plus extensible, avec des fonctionnalités de routage et de validation des routes, ainsi qu’un nouveau paquet wordpress/boot qui permet aux plugins de créer des pages personnalisées pour l’éditeur de site.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Et bien plus encore</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Pour un aperçu complet de toutes les nouvelles fonctionnalités et améliorations de WordPress 7.0, rendez-vous sur le site web présentant les nouveautés.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/download/releases/7-0\">Découvrez les nouveautés de la version 7.0 (en anglais)</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">En savoir plus sur WordPress 7.0</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/\">Learn WordPress (en anglais)</a> est une ressource gratuite destinée aux utilisateurs de WordPress, qu’ils soient novices ou expérimentés. Learn propose de nombreuses vidéos explicatives sur l’utilisation des différentes fonctionnalités de WordPress, des <a href=\"https://learn.wordpress.org/social-learning/\">ateliers interactifs (en anglais)</a> permettant d’approfondir certains sujets, ainsi que des plans de cours pour explorer en détail des domaines spécifiques de WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Consultez <a href=\"https://wordpress.org/documentation/wordpress-version/version-7.0\">les notes de mise à jour de WordPress 7.0 (en anglais)</a> pour obtenir des informations sur l’installation, les améliorations, les problèmes résolus, les contributeurs à cette version, les ressources d’apprentissage et la liste des modifications apportées aux fichiers.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Consultez le <a href=\"https://fr.wordpress.org/2026/05/15/guide-des-changements-techniques-de-wordpress-7-0/\">guide des changements techniques de WordPress 7.0</a> et découvrez les modifications apportées à cette version grâce à des notes détaillées destinées aux développeurs, qui vous aideront à créer des sites avec WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">L’équipe de direction de WordPress 7.0</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Chaque version vous est proposée par une équipe dévouée de contributeurs enthousiastes qui veillent à ce que tout se déroule comme prévu et sans accroc. L’équipe qui a piloté la version 7.0 est un groupe international et pluridisciplinaire de contributeurs toujours prêts à défendre des idées, à lever les obstacles et à résoudre les problèmes.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Direction générale : <a href=\"https://profiles.wordpress.org/matveb/\">Matias Ventura</a></li>\n\n\n\n<li>Coordination de la version : <a href=\"https://profiles.wordpress.org/chaion07/\">Ahmed Kabir Chaion</a>, <a href=\"https://profiles.wordpress.org/amykamala/\">Amy Kamala</a>, <a href=\"https://profiles.wordpress.org/4thhubbard/\">Mary Hubbard</a></li>\n\n\n\n<li>Direction technique : <a href=\"https://profiles.wordpress.org/ellatrix/\">Ella van Durpe</a>, <a href=\"https://profiles.wordpress.org/mukesh27/\">Mukesh Panchal</a>, <a href=\"https://profiles.wordpress.org/sergeybiryukov/\">Sergey Biryukov</a></li>\n\n\n\n<li>Gestion de projet : <a href=\"https://profiles.wordpress.org/audrasjb/\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/juanmaguitar/\">JuanMa Garrido</a></li>\n\n\n\n<li>Direction des tests : <a href=\"https://profiles.wordpress.org/ankit-k-gupta/\">Ankit K Gupta</a>, <a href=\"https://profiles.wordpress.org/marybaum/\">Mary Baum</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Merci aux contributeurs et contributrices</h2>\n\n\n\n<p class=\"wp-block-paragraph\">La mission de WordPress est de <a href=\"https://fr.wordpress.org/about/\">démocratiser la publication de contenu</a> et ce projet <a href=\"https://opensource.org/osd-annotated\">embrasse les libertés fondamentales de l’open-source (en anglais)</a>. Une communauté mondiale et diversifiée supporte cet effort.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0 reflète les efforts inlassables et la passion de plus de <strong>875 contributeurs issus de pays du monde entier</strong>. Cette version a également accueilli <strong>plus de 200 nouveaux contributeurs</strong> !</p>\n\n\n\n<p class=\"wp-block-paragraph\">Leur collaboration a permis d’apporter plus de <strong>420 améliorations et corrections</strong>, garantissant une version stable pour tous – ce qui témoigne de la puissance et des capacités de la communauté open source WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/1000camels/\">1000camels</a> · <a href=\"https://profiles.wordpress.org/aakashverma1/\">Aakash Verma</a> · <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a> · <a href=\"https://profiles.wordpress.org/aaronrobertshaw/\">Aaron Robertshaw</a> · <a href=\"https://profiles.wordpress.org/abdullah17/\">Abdullah Kaludi</a> · <a href=\"https://profiles.wordpress.org/abduremon/\">Abdur Rahman Emon</a> · <a href=\"https://profiles.wordpress.org/hiabhaykulkarni/\">Abhay Kulkarni</a> · <a href=\"https://profiles.wordpress.org/fitehal/\">Abhishek Deshpande</a> · <a href=\"https://profiles.wordpress.org/acmoifr/\">acmoifr</a> · <a href=\"https://profiles.wordpress.org/dannythedog/\">Adam</a> · <a href=\"https://profiles.wordpress.org/adamsilverstein/\">Adam Silverstein</a> · <a href=\"https://profiles.wordpress.org/zieladam/\">Adam Zieliński</a> · <a href=\"https://profiles.wordpress.org/oztaser/\">Adil Öztaşer</a> · <a href=\"https://profiles.wordpress.org/adithyanaik/\">adithyanaik</a> · <a href=\"https://profiles.wordpress.org/iamadisingh/\">Aditya Singh</a> · <a href=\"https://profiles.wordpress.org/adnanhyder/\">Adnan Hyder Pervez</a> · <a href=\"https://profiles.wordpress.org/adnanlimdi/\">adnan.limdi</a> · <a href=\"https://profiles.wordpress.org/adrmf25/\">adrmf25</a> · <a href=\"https://profiles.wordpress.org/afwebdev/\">afwebdev</a> · <a href=\"https://profiles.wordpress.org/agnieszkaszuba/\">Agnieszka Szuba</a> · <a href=\"https://profiles.wordpress.org/elazzabi/\">Ahmed</a> · <a href=\"https://profiles.wordpress.org/chaion07/\">Ahmed Kabir Chaion</a> · <a href=\"https://profiles.wordpress.org/ajitbohra/\">Ajit Bohra</a> · <a href=\"https://profiles.wordpress.org/wildworks/\">Aki Hamano</a> · <a href=\"https://profiles.wordpress.org/akshat2802/\">Akshat Kakkad</a> · <a href=\"https://profiles.wordpress.org/aljullu/\">Albert Juhé Lluveras</a