(80,	0,	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'<!-- HEADER -->\n<header class=\"bg-white/95 backdrop-blur-md sticky top-0 z-50 border-b border-slate-100 shadow-sm\">\n  <div class=\"max-w-7xl mx-auto px-6 h-20 flex items-center justify-between\">\n    <a href=\"http://isi-suptech.local/\" class=\"flex items-center gap-3 group flex-shrink-0\">\n      <div class=\"w-11 h-11 bg-primary rounded-xl flex items-center justify-center text-white font-black text-[15px] shadow-lg group-hover:bg-primary-mid transition-colors\">IS</div>\n      <div class=\"hidden sm:block\">\n        <div class=\"font-display font-extrabold text-xl text-primary tracking-tight leading-none\">ISI SUPTECH</div>\n        <div class=\"text-[10px] text-slate-400 font-semibold tracking-widest uppercase\">Institut Superieur d\'Informatique</div>\n      </div>\n    </a>\n    <nav class=\"hidden lg:flex items-center gap-8\">\n      <a href=\"http://isi-suptech.local/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Accueil</a>\n      <a href=\"http://isi-suptech.local/formations/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Formations</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"nav-link active font-display font-semibold text-sm text-primary\">Admissions</a>\n      <a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Vie Etudiante</a>\n      <a href=\"http://isi-suptech.local/a-propos/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">A Propos</a>\n      <a href=\"http://isi-suptech.local/contact/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Contact</a>\n    </nav>\n    <div class=\"flex items-center gap-3\">\n      <a href=\"#\" class=\"hidden md:inline text-sm font-semibold text-slate-500 hover:text-primary transition-colors px-3\">Espace Etudiant</a>\n      <a href=\"#formulaire\" class=\"bg-primary hover:bg-primary-mid text-white px-5 py-2.5 rounded-lg text-sm font-bold shadow-md hover:shadow-lg transition-all\">S\'inscrire</a>\n    </div>\n  </div>\n</header>\n\n<!-- HERO -->\n<section class=\"relative bg-primary-dark overflow-hidden py-24\">\n  <div class=\"absolute inset-0 opacity-10\" style=\"background-image:radial-gradient(circle at 1px 1px,rgba(255,255,255,.4) 1px,transparent 0);background-size:32px 32px\"></div>\n  <div class=\"relative max-w-7xl mx-auto px-6 flex flex-col lg:flex-row items-center gap-12\">\n    <div class=\"flex-1 anim-2\">\n      <div class=\"badge bg-gold/20 text-gold border border-gold/30 mb-5 anim-1\"><span class=\"material-symbols-outlined\" style=\"font-size:13px\">event</span>Rentree 2025-2026</div>\n      <h1 class=\"font-display font-black text-white text-5xl leading-tight mb-4\">Rejoignez ISI SUPTECH</h1>\n      <p class=\"text-white/70 text-lg leading-relaxed mb-8 max-w-lg\">Les candidatures pour la rentree 2025-2026 sont ouvertes. Decouvrez les etapes, les conditions et deposez votre dossier en ligne.</p>\n      <div class=\"grid grid-cols-3 gap-4\">\n        <div class=\"bg-white/10 rounded-xl p-4 text-center\"><div class=\"font-black text-gold text-2xl\">15</div><div class=\"text-white/60 text-xs mt-1\">Aout 2025</div><div class=\"text-white/40 text-xs\">Ouverture dossiers</div></div>\n        <div class=\"bg-white/10 rounded-xl p-4 text-center\"><div class=\"font-black text-gold text-2xl\">30</div><div class=\"text-white/60 text-xs mt-1\">Aout 2025</div><div class=\"text-white/40 text-xs\">Cloture dossiers</div></div>\n        <div class=\"bg-white/10 rounded-xl p-4 text-center\"><div class=\"font-black text-gold text-2xl\">Oct.</div><div class=\"text-white/60 text-xs mt-1\">2025</div><div class=\"text-white/40 text-xs\">Debut des cours</div></div>\n      </div>\n    </div>\n    <div class=\"w-full lg:w-96 flex-shrink-0\">\n      <img src=\"https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=600&amp;q=70\" class=\"rounded-2xl shadow-2xl object-cover w-full h-64 lg:h-80\" alt=\"Etudiants ISI\">\n    </div>\n  </div>\n</section>\n\n<!-- PROCESSUS -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <div class=\"text-center mb-12\">\n    <h2 class=\"font-display font-black text-4xl text-gray-900 mb-3\">Le processus d\'admission</h2>\n    <p class=\"text-slate-500 text-lg\">5 etapes simples pour rejoindre l\'ISI SUPTECH</p>\n  </div>\n  <div class=\"relative max-w-3xl mx-auto\">\n    <div class=\"space-y-0\">\n\n      <div class=\"relative flex gap-6 pb-10 step-line\">\n        <div class=\"w-10 h-10 bg-primary rounded-full flex items-center justify-center text-white font-black text-sm flex-shrink-0 z-10 shadow-lg\">1</div>\n        <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-6 flex-1\">\n          <h3 class=\"font-display font-bold text-gray-900 mb-2\">Choisir sa formation</h3>\n          <p class=\"text-slate-500 text-sm\">Consultez le catalogue des formations et identifiez le programme qui correspond a votre profil, vos ambitions et les prerequisites requis.</p>\n          <a href=\"http://isi-suptech.local/formations/\" class=\"inline-flex items-center gap-1 text-primary font-semibold text-sm mt-3 hover:gap-2 transition-all\">Voir les formations <span class=\"material-symbols-outlined\" style=\"font-size:16px\">arrow_forward</span></a>\n        </div>\n      </div>\n\n      <div class=\"relative flex gap-6 pb-10 step-line\">\n        <div class=\"w-10 h-10 bg-primary rounded-full flex items-center justify-center text-white font-black text-sm flex-shrink-0 z-10 shadow-lg\">2</div>\n        <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-6 flex-1\">\n          <h3 class=\"font-display font-bold text-gray-900 mb-2\">Preparer son dossier</h3>\n          <p class=\"text-slate-500 text-sm mb-3\">Rassemblez les documents necessaires :</p>\n          <ul class=\"space-y-1 text-sm text-slate-500\">\n            <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:16px\">check</span>Photocopies des releves de notes (3 dernieres annees)</li>\n            <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:16px\">check</span>Photocopie de la piece d\'identite ou passeport</li>\n            <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:16px\">check</span>Lettre de motivation (1 page max)</li>\n            <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:16px\">check</span>2 photos d\'identite recentes</li>\n            <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:16px\">check</span>CV pour les Masters</li>\n          </ul>\n        </div>\n      </div>\n\n      <div class=\"relative flex gap-6 pb-10 step-line\">\n        <div class=\"w-10 h-10 bg-primary rounded-full flex items-center justify-center text-white font-black text-sm flex-shrink-0 z-10 shadow-lg\">3</div>\n        <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-6 flex-1\">\n          <h3 class=\"font-display font-bold text-gray-900 mb-2\">Soumettre sa candidature</h3>\n          <p class=\"text-slate-500 text-sm\">Remplissez le formulaire en ligne ci-dessous ou deposez votre dossier physique au bureau des admissions (bâtiment A, RDC). Les dossiers incomplets ne seront pas traites.</p>\n        </div>\n      </div>\n\n      <div class=\"relative flex gap-6 pb-10 step-line\">\n        <div class=\"w-10 h-10 bg-primary rounded-full flex items-center justify-center text-white font-black text-sm flex-shrink-0 z-10 shadow-lg\">4</div>\n        <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-6 flex-1\">\n          <h3 class=\"font-display font-bold text-gray-900 mb-2\">Tests de selection</h3>\n          <p class=\"text-slate-500 text-sm\">Les candidats selectionnes sur dossier sont convoques pour : un test de logique (45 min, QCM) et un entretien individuel de motivation. Convocation envoyee par email 72h avant.</p>\n        </div>\n      </div>\n\n      <div class=\"relative flex gap-6\">\n        <div class=\"w-10 h-10 bg-gold rounded-full flex items-center justify-center text-gray-900 font-black text-sm flex-shrink-0 z-10 shadow-lg\">5</div>\n        <div class=\"bg-gold-light rounded-2xl border border-gold/20 p-6 flex-1\">\n          <h3 class=\"font-display font-bold text-gray-900 mb-2\">Confirmation d\'inscription</h3>\n          <p class=\"text-slate-600 text-sm\">Apres acceptation, vous recevez votre lettre d\'admission. Confirmez votre inscription en reglant les frais d\'inscription (150 000 FCFA) dans les 5 jours. Bienvenue a l\'ISI SUPTECH !</p>\n        </div>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n<!-- FORMULAIRE -->\n<section id=\"formulaire\" class=\"bg-white border-y border-slate-100 py-16\">\n  <div class=\"max-w-7xl mx-auto px-6\">\n    <div class=\"grid grid-cols-1 lg:grid-cols-3 gap-12\">\n\n      <!-- Infos -->\n      <div>\n        <h2 class=\"font-display font-black text-3xl text-gray-900 mb-3\">Candidature en ligne</h2>\n        <p class=\"text-slate-500 mb-8\">Remplissez ce formulaire et nous vous contacterons sous 48h ouvrees.</p>\n        <div class=\"space-y-5\">\n          <div class=\"flex items-start gap-4 p-4 bg-surface rounded-xl\">\n            <div class=\"w-10 h-10 bg-primary-light rounded-xl flex items-center justify-center flex-shrink-0\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:20px\">email</span></div>\n            <div><div class=\"font-semibold text-gray-900 text-sm\">Email</div><div class=\"text-slate-500 text-sm\">admissions@isi-suptech.ci</div></div>\n          </div>\n          <div class=\"flex items-start gap-4 p-4 bg-surface rounded-xl\">\n            <div class=\"w-10 h-10 bg-primary-light rounded-xl flex items-center justify-center flex-shrink-0\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:20px\">phone</span></div>\n            <div><div class=\"font-semibold text-gray-900 text-sm\">Telephone</div><div class=\"text-slate-500 text-sm\">+225 27 22 XX XX XX</div></div>\n          </div>\n          <div class=\"flex items-start gap-4 p-4 bg-surface rounded-xl\">\n            <div class=\"w-10 h-10 bg-primary-light rounded-xl flex items-center justify-center flex-shrink-0\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:20px\">schedule</span></div>\n            <div><div class=\"font-semibold text-gray-900 text-sm\">Horaires admissions</div><div class=\"text-slate-500 text-sm\">Lun-Ven : 8h - 17h</div></div>\n          </div>\n        </div>\n      </div>\n\n      <!-- Formulaire -->\n      <div class=\"lg:col-span-2\">\n        \n          <div class=\"grid grid-cols-1 md:grid-cols-2 gap-5\">\n            <div>\n              <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Nom <span class=\"text-red-500\">*</span></label>\n              \n            </div>\n            <div>\n              <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Prenoms <span class=\"text-red-500\">*</span></label>\n              \n            </div>\n          </div>\n          <div class=\"grid grid-cols-1 md:grid-cols-2 gap-5\">\n            <div>\n              <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Email <span class=\"text-red-500\">*</span></label>\n              \n            </div>\n            <div>\n              <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Telephone <span class=\"text-red-500\">*</span></label>\n              \n            </div>\n          </div>\n          <div>\n            <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Formation souhaitee <span class=\"text-red-500\">*</span></label>\n            \n              Choisissez une formation...\n              BTS Informatique de Gestion\n              Licence en Informatique\n              Licence Reseaux &amp; Telecoms\n              Licence Data Science &amp; BI\n              Licence Cybersecurite\n              Licence Management des SI\n              Master RESI\n              Master Ingenierie Logicielle\n              Master Intelligence Artificielle\n            \n          </div>\n          <div class=\"grid grid-cols-1 md:grid-cols-2 gap-5\">\n            <div>\n              <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Dernier diplome obtenu</label>\n              \n                Baccalaureat\n                BTS\n                Licence\n                Master 1\n              \n            </div>\n            <div>\n              <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Annee d\'obtention</label>\n              \n            </div>\n          </div>\n          <div>\n            <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Lettre de motivation <span class=\"text-red-500\">*</span></label>\n            <textarea rows=\"4\" class=\"w-full border border-slate-200 rounded-xl px-4 py-3 text-sm bg-white resize-none\"></textarea>\n          </div>\n          <div class=\"flex items-start gap-3\">\n            \n            <label for=\"cgu\" class=\"text-sm text-slate-600\">J\'accepte les <a href=\"#\" class=\"text-primary underline\">conditions d\'utilisation</a> et la politique de confidentialite d\'ISI SUPTECH.</label>\n          </div>\n          <button type=\"submit\" class=\"w-full bg-primary hover:bg-primary-mid text-white py-3.5 rounded-xl font-bold text-sm transition-colors flex items-center justify-center gap-2 shadow-lg\">\n            <span class=\"material-symbols-outlined\" style=\"font-size:18px\">send</span>\n            Soumettre ma candidature\n          </button>\n        \n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FRAIS &amp; BOURSES -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <div class=\"text-center mb-10\">\n    <h2 class=\"font-display font-black text-3xl text-gray-900 mb-2\">Frais de scolarite</h2>\n    <p class=\"text-slate-500\">Des tarifs accessibles et des facilites de paiement</p>\n  </div>\n  <div class=\"grid grid-cols-1 md:grid-cols-3 gap-6\">\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-7 text-center\">\n      <div class=\"badge bg-gold-light text-yellow-800 mx-auto mb-4\">BTS - 2 ans</div>\n      <div class=\"font-black text-4xl text-gray-900 mb-1\">1.2M</div>\n      <div class=\"text-slate-500 text-sm mb-5\">FCFA / an</div>\n      <ul class=\"space-y-2 text-sm text-slate-600 text-left mb-6\">\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-green-500\" style=\"font-size:16px\">check</span>Acces laboratoires 24/7</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-green-500\" style=\"font-size:16px\">check</span>Support pedagogique inclus</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-green-500\" style=\"font-size:16px\">check</span>Materiel de cours numerique</li>\n      </ul>\n      <a href=\"#formulaire\" class=\"block w-full text-center bg-primary text-white py-2.5 rounded-xl font-bold text-sm hover:bg-primary-mid transition-colors\">Candidater</a>\n    </div>\n    <div class=\"bg-primary rounded-2xl shadow-xl p-7 text-center border-4 border-gold relative\">\n      <div class=\"absolute -top-3 left-1/2 -translate-x-1/2 badge bg-gold text-gray-900\">Le plus choisi</div>\n      <div class=\"badge bg-white/15 text-white mx-auto mb-4\">Licence - 3 ans</div>\n      <div class=\"font-black text-4xl text-white mb-1\">1.8M</div>\n      <div class=\"text-white/60 text-sm mb-5\">FCFA / an</div>\n      <ul class=\"space-y-2 text-sm text-white/80 text-left mb-6\">\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px\">check</span>Tout BTS inclus</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px\">check</span>Stages en entreprise organises</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px\">check</span>Certifications preparatoires</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px\">check</span>Reseau alumni actif</li>\n      </ul>\n      <a href=\"#formulaire\" class=\"block w-full text-center bg-gold hover:bg-yellow-400 text-gray-900 py-2.5 rounded-xl font-bold text-sm transition-colors\">Candidater</a>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-7 text-center\">\n      <div class=\"badge bg-primary-light text-primary mx-auto mb-4\">Master - 2 ans</div>\n      <div class=\"font-black text-4xl text-gray-900 mb-1\">2.4M</div>\n      <div class=\"text-slate-500 text-sm mb-5\">FCFA / an</div>\n      <ul class=\"space-y-2 text-sm text-slate-600 text-left mb-6\">\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-green-500\" style=\"font-size:16px\">check</span>Tout Licence inclus</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-green-500\" style=\"font-size:16px\">check</span>Projets avec entreprises</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-green-500\" style=\"font-size:16px\">check</span>Certifications officielles</li>\n        <li class=\"flex items-center gap-2\"><span class=\"material-symbols-outlined text-green-500\" style=\"font-size:16px\">check</span>Coaching carriere individuel</li>\n      </ul>\n      <a href=\"#formulaire\" class=\"block w-full text-center bg-primary text-white py-2.5 rounded-xl font-bold text-sm hover:bg-primary-mid transition-colors\">Candidater</a>\n    </div>\n  </div>\n  <div class=\"mt-6 p-5 bg-surface rounded-xl border border-slate-100 text-center text-sm text-slate-500\">\n    <span class=\"material-symbols-outlined text-gold align-middle\" style=\"font-size:18px\">info</span>\n    Des facilites de paiement en 3 tranches sont disponibles. Des bourses d\'excellence sont attribuees aux meilleurs candidats. Contactez le bureau des admissions pour plus d\'informations.\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer class=\"bg-primary-dark text-white/60 py-12\">\n  <div class=\"max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-4 gap-8\">\n    <div class=\"md:col-span-2\">\n      <div class=\"flex items-center gap-3 mb-4\"><div class=\"w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white font-black text-sm\">IS</div><span class=\"font-display font-extrabold text-lg text-white\">ISI SUPTECH</span></div>\n      <p class=\"text-sm leading-relaxed\">Institut Superieur d\'Informatique et de Technologie. Former les experts numeriques du continent africain depuis 2003.</p>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Navigation</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li><a href=\"http://isi-suptech.local/\" class=\"hover:text-white transition-colors\">Accueil</a></li>\n        <li><a href=\"http://isi-suptech.local/formations/\" class=\"hover:text-white transition-colors\">Formations</a></li>\n        <li><a href=\"http://isi-suptech.local/admissions/\" class=\"hover:text-white transition-colors\">Admissions</a></li>\n        <li><a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"hover:text-white transition-colors\">Vie Etudiante</a></li>\n        <li><a href=\"http://isi-suptech.local/actualites/\" class=\"hover:text-white transition-colors\">Actualites</a></li>\n        <li><a href=\"http://isi-suptech.local/a-propos/\" class=\"hover:text-white transition-colors\">A Propos</a></li>\n        <li><a href=\"http://isi-suptech.local/contact/\" class=\"hover:text-white transition-colors\">Contact</a></li>\n      </ul>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Contact</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">location_on</span>Abidjan, Cocody - Cote d\'Ivoire</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">phone</span>+225 27 22 XX XX XX</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">mail</span>contact@isi-suptech.ci</li>\n      </ul>\n    </div>\n  </div>\n  <div class=\"max-w-7xl mx-auto px-6 mt-8 pt-6 border-t border-white/10 text-center text-xs\">&copy; 2025 ISI SUPTECH. Tous droits reserves.</div>\n</footer>',	'Admissions',	'',	'inherit',	'closed',	'closed',	'',	'41-revision-v1',	'',	'',	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'',	41,	'http://isi-suptech.local/?p=80',	0,	'revision',	'',	0),
(81,	0,	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'<!-- HEADER -->\n<header class=\"bg-white/95 backdrop-blur-md sticky top-0 z-50 border-b border-slate-100 shadow-sm\">\n  <div class=\"max-w-7xl mx-auto px-6 h-20 flex items-center justify-between\">\n    <a href=\"http://isi-suptech.local/\" class=\"flex items-center gap-3 group flex-shrink-0\">\n      <div class=\"w-11 h-11 bg-primary rounded-xl flex items-center justify-center text-white font-black text-[15px] shadow-lg group-hover:bg-primary-mid transition-colors\">IS</div>\n      <div class=\"hidden sm:block\">\n        <div class=\"font-display font-extrabold text-xl text-primary tracking-tight leading-none\">ISI SUPTECH</div>\n        <div class=\"text-[10px] text-slate-400 font-semibold tracking-widest uppercase\">Institut Superieur d\'Informatique</div>\n      </div>\n    </a>\n    <nav class=\"hidden lg:flex items-center gap-8\">\n      <a href=\"http://isi-suptech.local/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Accueil</a>\n      <a href=\"http://isi-suptech.local/formations/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Formations</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Admissions</a>\n      <a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"nav-link active font-display font-semibold text-sm text-primary\">Vie Etudiante</a>\n      <a href=\"http://isi-suptech.local/a-propos/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">A Propos</a>\n      <a href=\"http://isi-suptech.local/contact/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary transition-colors\">Contact</a>\n    </nav>\n    <div class=\"flex items-center gap-3\">\n      <a href=\"#\" class=\"hidden md:inline text-sm font-semibold text-slate-500 hover:text-primary transition-colors px-3\">Espace Etudiant</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"bg-primary hover:bg-primary-mid text-white px-5 py-2.5 rounded-lg text-sm font-bold shadow-md hover:shadow-lg transition-all\">S\'inscrire</a>\n    </div>\n  </div>\n</header>\n\n<!-- HERO -->\n<section class=\"relative overflow-hidden min-h-[420px] flex items-center\">\n  <div class=\"absolute inset-0\">\n    <img src=\"https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=1600&amp;q=70\" class=\"w-full h-full object-cover\" alt=\"\">\n    <div class=\"absolute inset-0 bg-gradient-to-r from-primary-dark/95 to-primary/70\"></div>\n  </div>\n  <div class=\"relative max-w-7xl mx-auto px-6 py-24\">\n    <div class=\"badge bg-gold/20 text-gold border border-gold/30 mb-5 anim-1\"><span class=\"material-symbols-outlined\" style=\"font-size:13px\">groups</span>Campus &amp; associations</div>\n    <h1 class=\"font-display font-black text-white text-5xl leading-tight mb-4 anim-2\">Vie Etudiante</h1>\n    <p class=\"text-white/70 text-lg max-w-xl anim-2\">Un campus vivant, des associations dynamiques, des evenements tech toute l\'annee. L\'ISI SUPTECH c\'est bien plus qu\'une simple formation.</p>\n  </div>\n</section>\n\n<!-- CAMPUS EN CHIFFRES -->\n<div class=\"bg-white border-b border-slate-100\">\n  <div class=\"max-w-7xl mx-auto px-6 py-6 grid grid-cols-2 md:grid-cols-4 gap-4 divide-x divide-slate-100\">\n    <div class=\"px-6 first:pl-0 text-center\"><div class=\"font-display font-black text-3xl text-primary\">1 200</div><div class=\"text-xs text-slate-500 mt-1\">Etudiants inscrits</div></div>\n    <div class=\"px-6 text-center\"><div class=\"font-display font-black text-3xl text-primary\">8</div><div class=\"text-xs text-slate-500 mt-1\">Associations actives</div></div>\n    <div class=\"px-6 text-center\"><div class=\"font-display font-black text-3xl text-primary\">12</div><div class=\"text-xs text-slate-500 mt-1\">Laboratoires equipes</div></div>\n    <div class=\"px-6 text-center\"><div class=\"font-display font-black text-3xl text-primary\">20+</div><div class=\"text-xs text-slate-500 mt-1\">Evenements / an</div></div>\n  </div>\n</div>\n\n<!-- GALERIE CAMPUS -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <h2 class=\"font-display font-black text-3xl text-gray-900 mb-2\">Le Campus</h2>\n  <p class=\"text-slate-500 mb-8\">Des infrastructures modernes au service de votre apprentissage</p>\n  <div class=\"grid grid-cols-2 md:grid-cols-4 grid-rows-2 gap-4 h-[480px]\">\n    <div class=\"col-span-2 row-span-2 img-zoom-wrap rounded-2xl overflow-hidden\">\n      <img src=\"https://images.unsplash.com/photo-1562774053-701939374585?w=800&amp;q=70\" class=\"w-full h-full object-cover transition-transform duration-500 hover:scale-105\" alt=\"Campus principal\">\n    </div>\n    <div class=\"img-zoom-wrap rounded-2xl overflow-hidden\">\n      <img src=\"https://images.unsplash.com/photo-1541829070764-84a7d30dd3f3?w=500&amp;q=70\" class=\"w-full h-full object-cover transition-transform duration-500 hover:scale-105\" alt=\"Labo informatique\">\n    </div>\n    <div class=\"img-zoom-wrap rounded-2xl overflow-hidden\">\n      <img src=\"https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=500&amp;q=70\" class=\"w-full h-full object-cover transition-transform duration-500 hover:scale-105\" alt=\"Salle TP\">\n    </div>\n    <div class=\"img-zoom-wrap rounded-2xl overflow-hidden\">\n      <img src=\"https://images.unsplash.com/photo-1497633762265-9d179a990aa6?w=500&amp;q=70\" class=\"w-full h-full object-cover transition-transform duration-500 hover:scale-105\" alt=\"Bibliotheque\">\n    </div>\n    <div class=\"img-zoom-wrap rounded-2xl overflow-hidden\">\n      <img src=\"https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=500&amp;q=70\" class=\"w-full h-full object-cover transition-transform duration-500 hover:scale-105\" alt=\"Salle coworking\">\n    </div>\n  </div>\n</section>\n\n<!-- INFRASTRUCTURES -->\n<section class=\"bg-white border-y border-slate-100 py-16\">\n  <div class=\"max-w-7xl mx-auto px-6\">\n    <h2 class=\"font-display font-black text-3xl text-gray-900 mb-2\">Nos infrastructures</h2>\n    <p class=\"text-slate-500 mb-10\">Des equipements de pointe pour une formation au niveau de l\'industrie</p>\n    <div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6\">\n      <div class=\"card-lift p-6 bg-surface rounded-2xl border border-slate-100\">\n        <div class=\"w-12 h-12 bg-primary-light rounded-xl flex items-center justify-center mb-4\"><span class=\"material-symbols-outlined text-primary text-2xl\">computer</span></div>\n        <h3 class=\"font-display font-bold text-gray-900 mb-2\">12 Laboratoires informatiques</h3>\n        <p class=\"text-slate-500 text-sm\">Plus de 300 postes de travail avec les dernieres configurations (Core i7, 32 Go RAM, SSD). Acces 24h/24 avec badge etudiant.</p>\n      </div>\n      <div class=\"card-lift p-6 bg-surface rounded-2xl border border-slate-100\">\n        <div class=\"w-12 h-12 bg-primary-light rounded-xl flex items-center justify-center mb-4\"><span class=\"material-symbols-outlined text-primary text-2xl\">hub</span></div>\n        <h3 class=\"font-display font-bold text-gray-900 mb-2\">Labo Reseaux &amp; Cisco</h3>\n        <p class=\"text-slate-500 text-sm\">Equipements Cisco certifies (routeurs, switchs, firewalls). Preparation aux certifications CCNA/CCNP. Racks physiques disponibles.</p>\n      </div>\n      <div class=\"card-lift p-6 bg-surface rounded-2xl border border-slate-100\">\n        <div class=\"w-12 h-12 bg-primary-light rounded-xl flex items-center justify-center mb-4\"><span class=\"material-symbols-outlined text-primary text-2xl\">cloud</span></div>\n        <h3 class=\"font-display font-bold text-gray-900 mb-2\">Cloud Lab &amp; Serveurs</h3>\n        <p class=\"text-slate-500 text-sm\">Infrastructure cloud privee (VMware, Proxmox) avec acces AWS et Azure pour les projets. Chaque etudiant dispose d\'un VPS personnel en Master.</p>\n      </div>\n      <div class=\"card-lift p-6 bg-surface rounded-2xl border border-slate-100\">\n        <div class=\"w-12 h-12 bg-primary-light rounded-xl flex items-center justify-center mb-4\"><span class=\"material-symbols-outlined text-primary text-2xl\">auto_stories</span></div>\n        <h3 class=\"font-display font-bold text-gray-900 mb-2\">Mediatheque numerique</h3>\n        <p class=\"text-slate-500 text-sm\">Acces illimite a plus de 5000 ressources numeriques : livres techniques, cours Udemy, formations LinkedIn Learning, IEEE papers.</p>\n      </div>\n      <div class=\"card-lift p-6 bg-surface rounded-2xl border border-slate-100\">\n        <div class=\"w-12 h-12 bg-primary-light rounded-xl flex items-center justify-center mb-4\"><span class=\"material-symbols-outlined text-primary text-2xl\">wifi</span></div>\n        <h3 class=\"font-display font-bold text-gray-900 mb-2\">WiFi Fibre sur tout le campus</h3>\n        <p class=\"text-slate-500 text-sm\">Connexion fibre optique 1 Gbps partagee. 100% du campus couvert. Acces VPN inclus pour les projets distants et le teletravail pedagogique.</p>\n      </div>\n      <div class=\"card-lift p-6 bg-surface rounded-2xl border border-slate-100\">\n        <div class=\"w-12 h-12 bg-primary-light rounded-xl flex items-center justify-center mb-4\"><span class=\"material-symbols-outlined text-primary text-2xl\">groups</span></div>\n        <h3 class=\"font-display font-bold text-gray-900 mb-2\">Espaces de coworking</h3>\n        <p class=\"text-slate-500 text-sm\">4 espaces de travail collaboratif avec tableaux blancs, TV pour les presentations et cabines phoniques pour les visioconferences.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ASSOCIATIONS -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <h2 class=\"font-display font-black text-3xl text-gray-900 mb-2\">Associations &amp; clubs</h2>\n  <p class=\"text-slate-500 mb-10\">Des espaces pour developper vos competences au-dela des cours</p>\n  <div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5\">\n\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 p-6 shadow-sm text-center\">\n      <div class=\"w-14 h-14 bg-gradient-to-br from-primary to-primary-mid rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\">\n        <span class=\"material-symbols-outlined text-white text-2xl\">code</span>\n      </div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">ISI Dev Club</h3>\n      <p class=\"text-slate-500 text-xs leading-relaxed mb-3\">Hackathons, projets open source, contributions GitHub. 180 membres actifs.</p>\n      <span class=\"badge bg-primary-light text-primary\">Programmation</span>\n    </div>\n\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 p-6 shadow-sm text-center\">\n      <div class=\"w-14 h-14 bg-gradient-to-br from-red-500 to-red-700 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\">\n        <span class=\"material-symbols-outlined text-white text-2xl\">security</span>\n      </div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">CyberISI</h3>\n      <p class=\"text-slate-500 text-xs leading-relaxed mb-3\">CTF competitions, pentesting ethique, workshops securite. Equipe nationale de CTF.</p>\n      <span class=\"badge bg-red-100 text-red-700\">Cybersecurite</span>\n    </div>\n\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 p-6 shadow-sm text-center\">\n      <div class=\"w-14 h-14 bg-gradient-to-br from-gold to-yellow-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\">\n        <span class=\"material-symbols-outlined text-white text-2xl\">rocket_launch</span>\n      </div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">ISI Startup</h3>\n      <p class=\"text-slate-500 text-xs leading-relaxed mb-3\">Incubateur de startups etudiantes. Mentoring, pitchs, financement des meilleurs projets.</p>\n      <span class=\"badge bg-gold-light text-yellow-800\">Entrepreneuriat</span>\n    </div>\n\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 p-6 shadow-sm text-center\">\n      <div class=\"w-14 h-14 bg-gradient-to-br from-green-500 to-green-700 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\">\n        <span class=\"material-symbols-outlined text-white text-2xl\">public</span>\n      </div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">ISI International</h3>\n      <p class=\"text-slate-500 text-xs leading-relaxed mb-3\">Echanges universitaires, conferences internationales, mobilite etudiante Europe/Canada.</p>\n      <span class=\"badge bg-green-100 text-green-700\">International</span>\n    </div>\n\n  </div>\n</section>\n\n<!-- EVENEMENTS A VENIR -->\n<section class=\"bg-primary-dark py-16\">\n  <div class=\"max-w-7xl mx-auto px-6\">\n    <h2 class=\"font-display font-black text-3xl text-white mb-2\">Prochains evenements</h2>\n    <p class=\"text-white/60 mb-10\">Ne manquez pas les rendez-vous de l\'annee</p>\n    <div class=\"grid grid-cols-1 md:grid-cols-3 gap-5\">\n      <div class=\"bg-white/10 backdrop-blur border border-white/15 rounded-2xl p-6\">\n        <div class=\"flex items-center gap-3 mb-4\">\n          <div class=\"w-14 h-14 bg-gold rounded-xl flex flex-col items-center justify-center flex-shrink-0 text-gray-900\">\n            <div class=\"font-black text-xl leading-none\">15</div>\n            <div class=\"text-xs font-semibold\">JUIN</div>\n          </div>\n          <div>\n            <div class=\"font-display font-bold text-white\">ISI Hackathon 2025</div>\n            <div class=\"text-white/50 text-xs\">48h non-stop - Equipes de 3-5</div>\n          </div>\n        </div>\n        <p class=\"text-white/60 text-sm\">Thematique : Solutions numeriques pour l\'Afrique. Prix : 1M, 500k et 250k FCFA. Ouvert a tous les etudiants.</p>\n      </div>\n      <div class=\"bg-white/10 backdrop-blur border border-white/15 rounded-2xl p-6\">\n        <div class=\"flex items-center gap-3 mb-4\">\n          <div class=\"w-14 h-14 bg-primary-mid rounded-xl flex flex-col items-center justify-center flex-shrink-0 text-white\">\n            <div class=\"font-black text-xl leading-none\">22</div>\n            <div class=\"text-xs font-semibold\">JUIL</div>\n          </div>\n          <div>\n            <div class=\"font-display font-bold text-white\">Forum des entreprises</div>\n            <div class=\"text-white/50 text-xs\">Journee emploi - 60 entreprises</div>\n          </div>\n        </div>\n        <p class=\"text-white/60 text-sm\">Rencontrez les recruteurs des grandes entreprises IT d\'Afrique de l\'Ouest. CV, entretiens et offres de stage/CDI.</p>\n      </div>\n      <div class=\"bg-white/10 backdrop-blur border border-white/15 rounded-2xl p-6\">\n        <div class=\"flex items-center gap-3 mb-4\">\n          <div class=\"w-14 h-14 bg-green-600 rounded-xl flex flex-col items-center justify-center flex-shrink-0 text-white\">\n            <div class=\"font-black text-xl leading-none\">05</div>\n            <div class=\"text-xs font-semibold\">SEPT</div>\n          </div>\n          <div>\n            <div class=\"font-display font-bold text-white\">CTF CyberISI Challenge</div>\n            <div class=\"text-white/50 text-xs\">Competition capture-the-flag</div>\n          </div>\n        </div>\n        <p class=\"text-white/60 text-sm\">Competition nationale de cybersecurite. Epreuves de hacking ethique, crypto, forensics. Ouverte aux etablissements partenaires.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- TEMOIGNAGES VIE ETU -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <h2 class=\"font-display font-black text-3xl text-gray-900 mb-10 text-center\">Ils racontent leur vie a l\'ISI</h2>\n  <div class=\"grid grid-cols-1 md:grid-cols-3 gap-6\">\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-7\">\n      <p class=\"text-slate-600 italic text-sm leading-relaxed mb-5\">\"Le ISI Dev Club m\'a permis de contribuer a des projets concrets. J\'ai appris plus en 6 mois de club que dans certains cours. L\'ambiance est excellente.\"</p>\n      <div class=\"flex items-center gap-3\">\n        <div class=\"w-10 h-10 rounded-full bg-primary-light flex items-center justify-center font-bold text-primary text-sm\">AK</div>\n        <div><div class=\"font-semibold text-gray-900 text-sm\">Amara Kone</div><div class=\"text-xs text-slate-500\">L2 Informatique</div></div>\n      </div>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-7\">\n      <p class=\"text-slate-600 italic text-sm leading-relaxed mb-5\">\"Grace au Forum des entreprises de l\'ISI, j\'ai signe mon contrat de stage avant meme la fin de ma 3eme annee. Le reseau alumni est tres actif.\"</p>\n      <div class=\"flex items-center gap-3\">\n        <div class=\"w-10 h-10 rounded-full bg-gold-light flex items-center justify-center font-bold text-yellow-800 text-sm\">SM</div>\n        <div><div class=\"font-semibold text-gray-900 text-sm\">Safiatou Mbaye</div><div class=\"text-xs text-slate-500\">M1 RESI</div></div>\n      </div>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-7\">\n      <p class=\"text-slate-600 italic text-sm leading-relaxed mb-5\">\"Les labos sont vraiment bien equipes. Avoir des serveurs physiques pour pratiquer le reseau, c\'est quelque chose que peu d\'ecoles offrent en Afrique.\"</p>\n      <div class=\"flex items-center gap-3\">\n        <div class=\"w-10 h-10 rounded-full bg-green-100 flex items-center justify-center font-bold text-green-800 text-sm\">YT</div>\n        <div><div class=\"font-semibold text-gray-900 text-sm\">Yves Traore</div><div class=\"text-xs text-slate-500\">L3 Reseaux</div></div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer class=\"bg-primary-dark text-white/60 py-12\">\n  <div class=\"max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-4 gap-8\">\n    <div class=\"md:col-span-2\">\n      <div class=\"flex items-center gap-3 mb-4\"><div class=\"w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white font-black text-sm\">IS</div><span class=\"font-display font-extrabold text-lg text-white\">ISI SUPTECH</span></div>\n      <p class=\"text-sm leading-relaxed\">Institut Superieur d\'Informatique et de Technologie. Former les experts numeriques du continent africain depuis 2003.</p>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Navigation</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li><a href=\"http://isi-suptech.local/\" class=\"hover:text-white transition-colors\">Accueil</a></li>\n        <li><a href=\"http://isi-suptech.local/formations/\" class=\"hover:text-white transition-colors\">Formations</a></li>\n        <li><a href=\"http://isi-suptech.local/admissions/\" class=\"hover:text-white transition-colors\">Admissions</a></li>\n        <li><a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"hover:text-white transition-colors\">Vie Etudiante</a></li>\n        <li><a href=\"http://isi-suptech.local/actualites/\" class=\"hover:text-white transition-colors\">Actualites</a></li>\n        <li><a href=\"http://isi-suptech.local/a-propos/\" class=\"hover:text-white transition-colors\">A Propos</a></li>\n        <li><a href=\"http://isi-suptech.local/contact/\" class=\"hover:text-white transition-colors\">Contact</a></li>\n      </ul>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Contact</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">location_on</span>Abidjan, Cocody - Cote d\'Ivoire</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">phone</span>+225 27 22 XX XX XX</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">mail</span>contact@isi-suptech.ci</li>\n      </ul>\n    </div>\n  </div>\n  <div class=\"max-w-7xl mx-auto px-6 mt-8 pt-6 border-t border-white/10 text-center text-xs\">&copy; 2025 ISI SUPTECH. Tous droits reserves.</div>\n</footer>',	'Vie Etudiante',	'',	'inherit',	'closed',	'closed',	'',	'43-revision-v1',	'',	'',	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'',	43,	'http://isi-suptech.local/?p=81',	0,	'revision',	'',	0),
(82,	0,	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'<!-- HEADER -->\n<header class=\"bg-white/95 backdrop-blur-md sticky top-0 z-50 border-b border-slate-100 shadow-sm\">\n  <div class=\"max-w-7xl mx-auto px-6 h-20 flex items-center justify-between\">\n    <a href=\"http://isi-suptech.local/\" class=\"flex items-center gap-3 group flex-shrink-0\">\n      <div class=\"w-11 h-11 bg-primary rounded-xl flex items-center justify-center text-white font-black text-[15px] shadow-lg group-hover:bg-primary-mid transition-colors\">IS</div>\n      <div class=\"hidden sm:block\">\n        <div class=\"font-display font-extrabold text-xl text-primary tracking-tight leading-none\">ISI SUPTECH</div>\n        <div class=\"text-[10px] text-slate-400 font-semibold tracking-widest uppercase\">Institut Superieur d\'Informatique</div>\n      </div>\n    </a>\n    <nav class=\"hidden lg:flex items-center gap-8\">\n      <a href=\"http://isi-suptech.local/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Accueil</a>\n      <a href=\"http://isi-suptech.local/formations/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Formations</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Admissions</a>\n      <a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Vie Etudiante</a>\n      <a href=\"http://isi-suptech.local/a-propos/\" class=\"nav-link active font-display font-semibold text-sm text-primary\">A Propos</a>\n      <a href=\"http://isi-suptech.local/contact/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Contact</a>\n    </nav>\n    <div class=\"flex items-center gap-3\">\n      <a href=\"#\" class=\"hidden md:inline text-sm font-semibold text-slate-500 hover:text-primary px-3\">Espace Etudiant</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"bg-primary hover:bg-primary-mid text-white px-5 py-2.5 rounded-lg text-sm font-bold shadow-md transition-all\">S\'inscrire</a>\n    </div>\n  </div>\n</header>\n\n<!-- HERO -->\n<section class=\"relative overflow-hidden min-h-[440px] flex items-center\">\n  <div class=\"absolute inset-0\">\n    <img src=\"https://images.unsplash.com/photo-1562774053-701939374585?w=1600&amp;q=70\" class=\"w-full h-full object-cover\" alt=\"\">\n    <div class=\"absolute inset-0 bg-gradient-to-r from-primary-dark/96 to-primary-dark/70\"></div>\n  </div>\n  <div class=\"relative max-w-7xl mx-auto px-6 py-24 flex flex-col lg:flex-row items-center gap-16\">\n    <div class=\"flex-1\">\n      <div class=\"badge bg-gold/20 text-gold border border-gold/30 mb-5 anim-1\"><span class=\"material-symbols-outlined\" style=\"font-size:13px\">info</span>Notre histoire</div>\n      <h1 class=\"font-display font-black text-white text-5xl leading-tight mb-4 anim-2\">A Propos d\'ISI SUPTECH</h1>\n      <p class=\"text-white/70 text-lg leading-relaxed max-w-xl anim-2\">Depuis 2003, ISI SUPTECH forme les meilleurs specialistes IT d\'Afrique de l\'Ouest. Plus de 5000 laureats dans 18 pays. Une institution de reference.</p>\n    </div>\n    <div class=\"grid grid-cols-2 gap-4 flex-shrink-0 w-full lg:w-80\">\n      <div class=\"bg-white/10 border border-white/15 rounded-2xl p-5 text-center\"><div class=\"font-black text-gold text-4xl\">22</div><div class=\"text-white/60 text-xs mt-1\">Annees d\'existence</div></div>\n      <div class=\"bg-white/10 border border-white/15 rounded-2xl p-5 text-center\"><div class=\"font-black text-gold text-4xl\">5k+</div><div class=\"text-white/60 text-xs mt-1\">Laureats diplomes</div></div>\n      <div class=\"bg-white/10 border border-white/15 rounded-2xl p-5 text-center\"><div class=\"font-black text-gold text-4xl\">18</div><div class=\"text-white/60 text-xs mt-1\">Pays representes</div></div>\n      <div class=\"bg-white/10 border border-white/15 rounded-2xl p-5 text-center\"><div class=\"font-black text-gold text-4xl\">85+</div><div class=\"text-white/60 text-xs mt-1\">Enseignants experts</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- MISSION &amp; VALEURS -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <div class=\"grid grid-cols-1 lg:grid-cols-2 gap-12 items-center mb-16\">\n    <div>\n      <h2 class=\"font-display font-black text-4xl text-gray-900 mb-5\">Notre Mission</h2>\n      <p class=\"text-slate-600 text-lg leading-relaxed mb-5\">ISI SUPTECH a pour mission de former des professionnels de haut niveau, capables de concevoir, deployer et gerer les systemes d\'information et les infrastructures technologiques qui soutiennent le developpement economique de l\'Afrique.</p>\n      <p class=\"text-slate-600 leading-relaxed\">Nous croyons que l\'education technologique de qualite est le levier le plus puissant pour la transformation numerique du continent. Chaque etudiant forme est un agent de changement potentiel.</p>\n    </div>\n    <div class=\"relative\">\n      <img src=\"https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=700&amp;q=70\" class=\"rounded-2xl shadow-xl w-full h-72 object-cover\" alt=\"\">\n      <div class=\"absolute -bottom-5 -left-5 bg-primary rounded-xl p-4 shadow-xl\">\n        <div class=\"font-black text-gold text-3xl\">N°1</div>\n        <div class=\"text-white/70 text-xs\">Ecole IT en Cote d\'Ivoire</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Valeurs -->\n  <h2 class=\"font-display font-black text-3xl text-gray-900 mb-8 text-center\">Nos valeurs fondatrices</h2>\n  <div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5\">\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 shadow-sm p-6 text-center\">\n      <div class=\"w-14 h-14 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\"><span class=\"material-symbols-outlined text-white text-2xl\">workspace_premium</span></div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">Excellence</h3>\n      <p class=\"text-slate-500 text-sm\">Nous visons les plus hauts standards dans l\'enseignement, la recherche et l\'insertion professionnelle.</p>\n    </div>\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 shadow-sm p-6 text-center\">\n      <div class=\"w-14 h-14 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\"><span class=\"material-symbols-outlined text-white text-2xl\">lightbulb</span></div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">Innovation</h3>\n      <p class=\"text-slate-500 text-sm\">Nous encourageons la crativite, l\'entrepreneuriat technologique et la culture de l\'experimentation.</p>\n    </div>\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 shadow-sm p-6 text-center\">\n      <div class=\"w-14 h-14 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\"><span class=\"material-symbols-outlined text-white text-2xl\">handshake</span></div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">Integrite</h3>\n      <p class=\"text-slate-500 text-sm\">L\'honnetete intellectuelle, l\'ethique professionnelle et le respect mutuel guident toutes nos actions.</p>\n    </div>\n    <div class=\"card-lift bg-white rounded-2xl border border-slate-100 shadow-sm p-6 text-center\">\n      <div class=\"w-14 h-14 bg-primary rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg\"><span class=\"material-symbols-outlined text-white text-2xl\">public</span></div>\n      <h3 class=\"font-display font-bold text-gray-900 mb-2\">Impact Africain</h3>\n      <p class=\"text-slate-500 text-sm\">Nous formons des talents qui contribuent au developpement numerique et economique de l\'Afrique.</p>\n    </div>\n  </div>\n</section>\n\n<!-- TIMELINE HISTORIQUE -->\n<section class=\"bg-primary-dark py-16\">\n  <div class=\"max-w-7xl mx-auto px-6\">\n    <h2 class=\"font-display font-black text-3xl text-white mb-2\">Notre histoire</h2>\n    <p class=\"text-white/60 mb-12\">Deux decennies de croissance et d\'excellence</p>\n    <div class=\"relative max-w-2xl border-l-2 border-primary-mid pl-8 ml-4\">\n      <div class=\"timeline-item relative mb-10\">\n        <div class=\"font-black text-gold text-lg mb-1\">2003</div>\n        <h3 class=\"font-display font-bold text-white mb-2\">Fondation de l\'ISI</h3>\n        <p class=\"text-white/60 text-sm\">Creation de l\'Institut Superieur d\'Informatique a Abidjan avec 3 formations et 120 etudiants. Vision : former les specialistes IT dont l\'Afrique a besoin.</p>\n      </div>\n      <div class=\"timeline-item relative mb-10\">\n        <div class=\"font-black text-gold text-lg mb-1\">2008</div>\n        <h3 class=\"font-display font-bold text-white mb-2\">Accreditation nationale</h3>\n        <p class=\"text-white/60 text-sm\">Obtention de l\'accreditation du Ministere de l\'Enseignement Superieur. Lancement des premiers programmes de Licence reconnus par l\'Etat.</p>\n      </div>\n      <div class=\"timeline-item relative mb-10\">\n        <div class=\"font-black text-gold text-lg mb-1\">2013</div>\n        <h3 class=\"font-display font-bold text-white mb-2\">Lancement des Masters</h3>\n        <p class=\"text-white/60 text-sm\">Ouverture du programme Master RESI, qui deviendra le fleuron de l\'institution. 1000eme etudiant diplome. Demenagement sur le campus actuel de Cocody.</p>\n      </div>\n      <div class=\"timeline-item relative mb-10\">\n        <div class=\"font-black text-gold text-lg mb-1\">2018</div>\n        <h3 class=\"font-display font-bold text-white mb-2\">Partenariats internationaux</h3>\n        <p class=\"text-white/60 text-sm\">Conventions avec des universites francaises (ESIEA, ISEP) et canadiennes (UQAM). Programme d\'echanges etudiants. Cisco Academy officielle.</p>\n      </div>\n      <div class=\"timeline-item relative\">\n        <div class=\"font-black text-gold text-lg mb-1\">2025</div>\n        <h3 class=\"font-display font-bold text-white mb-2\">ISI SUPTECH 2.0</h3>\n        <p class=\"text-white/60 text-sm\">Nouveau nom, nouveau campus, nouveau laboratoire IA. 1200 etudiants, 12 programmes, 5000+ laureats dans 18 pays. Le meilleur reste a venir.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- EQUIPE DIRIGEANTE -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <h2 class=\"font-display font-black text-3xl text-gray-900 mb-2 text-center\">Equipe de direction</h2>\n  <p class=\"text-slate-500 text-center mb-10\">Des leaders experts au service de votre reussite</p>\n  <div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6\">\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden text-center\">\n      <div class=\"h-48 overflow-hidden\">\n        <img src=\"https://images.unsplash.com/photo-1560250097-0b93528c311a?w=400&amp;q=70\" class=\"w-full h-full object-cover object-top\" alt=\"\">\n      </div>\n      <div class=\"p-5\">\n        <h4 class=\"font-display font-bold text-gray-900\">Prof. Kouadio N\'Dri</h4>\n        <div class=\"text-primary text-xs font-semibold mt-1 mb-2\">Directeur General</div>\n        <p class=\"text-slate-500 text-xs\">PhD Informatique - Universite de Montpellier. 20 ans d\'experience dans l\'enseignement superieur technologique.</p>\n      </div>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden text-center\">\n      <div class=\"h-48 overflow-hidden\">\n        <img src=\"https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=400&amp;q=70\" class=\"w-full h-full object-cover object-top\" alt=\"\">\n      </div>\n      <div class=\"p-5\">\n        <h4 class=\"font-display font-bold text-gray-900\">Dr. Awa Sow</h4>\n        <div class=\"text-primary text-xs font-semibold mt-1 mb-2\">Directrice Pedagogique</div>\n        <p class=\"text-slate-500 text-xs\">PhD Systemes d\'Information - ESCP. Ancienne DSI chez MTN Cote d\'Ivoire. Specialiste en innovation pedagogique.</p>\n      </div>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden text-center\">\n      <div class=\"h-48 overflow-hidden\">\n        <img src=\"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&amp;q=70\" class=\"w-full h-full object-cover object-top\" alt=\"\">\n      </div>\n      <div class=\"p-5\">\n        <h4 class=\"font-display font-bold text-gray-900\">M. Ibrahima Balde</h4>\n        <div class=\"text-primary text-xs font-semibold mt-1 mb-2\">Directeur des Etudes</div>\n        <p class=\"text-slate-500 text-xs\">Ingenieur INSA Lyon. Certifie Cisco CCIE, AWS Solutions Architect. Ex-consultant Senior chez Capgemini.</p>\n      </div>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden text-center\">\n      <div class=\"h-48 overflow-hidden\">\n        <img src=\"https://images.unsplash.com/photo-1580489944761-15a19d654956?w=400&amp;q=70\" class=\"w-full h-full object-cover object-top\" alt=\"\">\n      </div>\n      <div class=\"p-5\">\n        <h4 class=\"font-display font-bold text-gray-900\">Mme Fatou Diagne</h4>\n        <div class=\"text-primary text-xs font-semibold mt-1 mb-2\">Responsable Admissions</div>\n        <p class=\"text-slate-500 text-xs\">MBA Management - EMLYON. 10 ans dans l\'orientation et l\'accompagnement etudiant dans les ecoles d\'excellence africaines.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- PARTENAIRES -->\n<section class=\"bg-white border-y border-slate-100 py-14\">\n  <div class=\"max-w-7xl mx-auto px-6 text-center\">\n    <h2 class=\"font-display font-bold text-xl text-gray-900 mb-2\">Partenaires institutionnels &amp; entreprises</h2>\n    <p class=\"text-slate-500 text-sm mb-10\">Ils font confiance a ISI SUPTECH pour leurs recrutements et projets</p>\n    <div class=\"grid grid-cols-3 md:grid-cols-6 gap-4 items-center\">\n      <div class=\"bg-surface rounded-xl p-4 flex items-center justify-center h-16 grayscale hover:grayscale-0 transition-all\"><div class=\"font-black text-primary text-lg\">Cisco</div></div>\n      <div class=\"bg-surface rounded-xl p-4 flex items-center justify-center h-16 grayscale hover:grayscale-0 transition-all\"><div class=\"font-black text-orange-600 text-lg\">AWS</div></div>\n      <div class=\"bg-surface rounded-xl p-4 flex items-center justify-center h-16 grayscale hover:grayscale-0 transition-all\"><div class=\"font-black text-blue-600 text-lg\">MTN</div></div>\n      <div class=\"bg-surface rounded-xl p-4 flex items-center justify-center h-16 grayscale hover:grayscale-0 transition-all\"><div class=\"font-black text-red-600 text-lg\">Orange</div></div>\n      <div class=\"bg-surface rounded-xl p-4 flex items-center justify-center h-16 grayscale hover:grayscale-0 transition-all\"><div class=\"font-black text-green-700 text-lg\">Microsoft</div></div>\n      <div class=\"bg-surface rounded-xl p-4 flex items-center justify-center h-16 grayscale hover:grayscale-0 transition-all\"><div class=\"font-black text-slate-700 text-lg\">IBM</div></div>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer class=\"bg-primary-dark text-white/60 py-12\">\n  <div class=\"max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-4 gap-8\">\n    <div class=\"md:col-span-2\">\n      <div class=\"flex items-center gap-3 mb-4\"><div class=\"w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white font-black text-sm\">IS</div><span class=\"font-display font-extrabold text-lg text-white\">ISI SUPTECH</span></div>\n      <p class=\"text-sm leading-relaxed\">Institut Superieur d\'Informatique et de Technologie. Former les experts numeriques du continent africain depuis 2003.</p>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Navigation</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li><a href=\"http://isi-suptech.local/\" class=\"hover:text-white transition-colors\">Accueil</a></li>\n        <li><a href=\"http://isi-suptech.local/formations/\" class=\"hover:text-white transition-colors\">Formations</a></li>\n        <li><a href=\"http://isi-suptech.local/admissions/\" class=\"hover:text-white transition-colors\">Admissions</a></li>\n        <li><a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"hover:text-white transition-colors\">Vie Etudiante</a></li>\n        <li><a href=\"http://isi-suptech.local/actualites/\" class=\"hover:text-white transition-colors\">Actualites</a></li>\n        <li><a href=\"http://isi-suptech.local/a-propos/\" class=\"hover:text-white transition-colors\">A Propos</a></li>\n        <li><a href=\"http://isi-suptech.local/contact/\" class=\"hover:text-white transition-colors\">Contact</a></li>\n      </ul>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Contact</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">location_on</span>Abidjan, Cocody - Cote d\'Ivoire</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">phone</span>+225 27 22 XX XX XX</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">mail</span>contact@isi-suptech.ci</li>\n      </ul>\n    </div>\n  </div>\n  <div class=\"max-w-7xl mx-auto px-6 mt-8 pt-6 border-t border-white/10 text-center text-xs\">&copy; 2025 ISI SUPTECH. Tous droits reserves.</div>\n</footer>',	'A Propos',	'',	'inherit',	'closed',	'closed',	'',	'45-revision-v1',	'',	'',	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'',	45,	'http://isi-suptech.local/?p=82',	0,	'revision',	'',	