(83,	0,	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'<!-- HEADER -->\n<header class=\"bg-white/95 backdrop-blur-md sticky top-0 z-50 border-b border-slate-100 shadow-sm\">\n  <div class=\"max-w-7xl mx-auto px-6 h-20 flex items-center justify-between\">\n    <a href=\"http://isi-suptech.local/\" class=\"flex items-center gap-3 group flex-shrink-0\">\n      <div class=\"w-11 h-11 bg-primary rounded-xl flex items-center justify-center text-white font-black text-[15px] shadow-lg group-hover:bg-primary-mid transition-colors\">IS</div>\n      <div class=\"hidden sm:block\">\n        <div class=\"font-display font-extrabold text-xl text-primary tracking-tight leading-none\">ISI SUPTECH</div>\n        <div class=\"text-[10px] text-slate-400 font-semibold tracking-widest uppercase\">Institut Superieur d\'Informatique</div>\n      </div>\n    </a>\n    <nav class=\"hidden lg:flex items-center gap-8\">\n      <a href=\"http://isi-suptech.local/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Accueil</a>\n      <a href=\"http://isi-suptech.local/formations/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Formations</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Admissions</a>\n      <a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Vie Etudiante</a>\n      <a href=\"http://isi-suptech.local/a-propos/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">A Propos</a>\n      <a href=\"http://isi-suptech.local/contact/\" class=\"nav-link active font-display font-semibold text-sm text-primary\">Contact</a>\n    </nav>\n    <div class=\"flex items-center gap-3\">\n      <a href=\"#\" class=\"hidden md:inline text-sm font-semibold text-slate-500 hover:text-primary px-3\">Espace Etudiant</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"bg-primary hover:bg-primary-mid text-white px-5 py-2.5 rounded-lg text-sm font-bold shadow-md transition-all\">S\'inscrire</a>\n    </div>\n  </div>\n</header>\n\n<!-- HERO -->\n<section class=\"bg-primary-dark py-20 relative overflow-hidden\">\n  <div class=\"absolute inset-0 opacity-10\" style=\"background-image:radial-gradient(circle at 1px 1px,rgba(255,255,255,.4) 1px,transparent 0);background-size:32px 32px\"></div>\n  <div class=\"relative max-w-7xl mx-auto px-6\">\n    <div class=\"badge bg-gold/20 text-gold border border-gold/30 mb-5 anim-1\"><span class=\"material-symbols-outlined\" style=\"font-size:13px\">contact_support</span>Nous joindre</div>\n    <h1 class=\"font-display font-black text-white text-5xl mb-4 anim-2\">Contact &amp; FAQ</h1>\n    <p class=\"text-white/70 text-lg max-w-xl anim-2\">Une question sur nos formations, l\'admission ou la vie sur campus ? Consultez notre FAQ ou contactez-nous directement.</p>\n  </div>\n</section>\n\n<!-- CONTACT CARDS -->\n<section class=\"max-w-7xl mx-auto px-6 -mt-6 relative z-10 pb-0\">\n  <div class=\"grid grid-cols-1 md:grid-cols-3 gap-5\">\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-lg p-6 flex gap-4 items-start\">\n      <div class=\"w-12 h-12 bg-primary rounded-xl flex items-center justify-center flex-shrink-0 shadow-md\"><span class=\"material-symbols-outlined text-white text-xl\">location_on</span></div>\n      <div>\n        <div class=\"font-display font-bold text-gray-900 mb-1\">Adresse</div>\n        <div class=\"text-slate-500 text-sm\">ISI SUPTECH, Cocody Angre<br>BP 12345, Abidjan 08<br>Cote d\'Ivoire</div>\n      </div>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-lg p-6 flex gap-4 items-start\">\n      <div class=\"w-12 h-12 bg-primary rounded-xl flex items-center justify-center flex-shrink-0 shadow-md\"><span class=\"material-symbols-outlined text-white text-xl\">phone</span></div>\n      <div>\n        <div class=\"font-display font-bold text-gray-900 mb-1\">Telephone</div>\n        <div class=\"text-slate-500 text-sm\">Accueil : +225 27 22 XX XX XX<br>Admissions : +225 07 XX XX XX XX<br>Urgences : +225 05 XX XX XX XX</div>\n      </div>\n    </div>\n    <div class=\"bg-white rounded-2xl border border-slate-100 shadow-lg p-6 flex gap-4 items-start\">\n      <div class=\"w-12 h-12 bg-primary rounded-xl flex items-center justify-center flex-shrink-0 shadow-md\"><span class=\"material-symbols-outlined text-white text-xl\">schedule</span></div>\n      <div>\n        <div class=\"font-display font-bold text-gray-900 mb-1\">Horaires d\'ouverture</div>\n        <div class=\"text-slate-500 text-sm\">Lun - Ven : 7h30 - 18h00<br>Samedi : 8h00 - 13h00<br>Dimanche : Ferme</div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FORMULAIRE + CARTE -->\n<section class=\"max-w-7xl mx-auto px-6 py-16\">\n  <div class=\"grid grid-cols-1 lg:grid-cols-2 gap-12\">\n\n    <!-- Formulaire -->\n    <div>\n      <h2 class=\"font-display font-black text-3xl text-gray-900 mb-2\">Envoyez-nous un message</h2>\n      <p class=\"text-slate-500 mb-7\">Nous repondons sous 24 a 48h ouvrees.</p>\n      \n        <div class=\"grid grid-cols-1 md:grid-cols-2 gap-5\">\n          <div>\n            <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Nom <span class=\"text-red-500\">*</span></label>\n            \n          </div>\n          <div>\n            <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Prenom <span class=\"text-red-500\">*</span></label>\n            \n          </div>\n        </div>\n        <div>\n          <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Email <span class=\"text-red-500\">*</span></label>\n          \n        </div>\n        <div>\n          <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Objet <span class=\"text-red-500\">*</span></label>\n          \n            Selectionnez un objet...\n            Information sur les formations\n            Processus d\'admission\n            Frais de scolarite\n            Stages et partenariats entreprise\n            Vie sur le campus\n            Autre demande\n          \n        </div>\n        <div>\n          <label class=\"block text-sm font-semibold text-gray-700 mb-2\">Message <span class=\"text-red-500\">*</span></label>\n          <textarea rows=\"5\" class=\"w-full border border-slate-200 rounded-xl px-4 py-3 text-sm bg-white resize-none\"></textarea>\n        </div>\n        <button type=\"submit\" class=\"w-full bg-primary hover:bg-primary-mid text-white py-3.5 rounded-xl font-bold text-sm transition-colors flex items-center justify-center gap-2 shadow-lg\">\n          <span class=\"material-symbols-outlined\" style=\"font-size:18px\">send</span>\n          Envoyer le message\n        </button>\n      \n    </div>\n\n    <!-- Carte + Departments -->\n    <div class=\"space-y-6\">\n      <!-- Carte simulee -->\n      <div class=\"bg-primary-light/30 rounded-2xl overflow-hidden border border-primary-light h-64 flex items-center justify-center relative\">\n        <img src=\"https://images.unsplash.com/photo-1524661135-423995f22d0b?w=700&amp;q=70\" class=\"w-full h-full object-cover opacity-40\" alt=\"\">\n        <div class=\"absolute inset-0 flex items-center justify-center\">\n          <div class=\"bg-primary text-white rounded-2xl px-6 py-4 shadow-xl text-center\">\n            <span class=\"material-symbols-outlined text-gold text-3xl block mb-1\">location_on</span>\n            <div class=\"font-bold\">ISI SUPTECH</div>\n            <div class=\"text-white/70 text-xs\">Cocody Angre, Abidjan</div>\n          </div>\n        </div>\n      </div>\n\n      <!-- Contacts par departement -->\n      <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-6\">\n        <h3 class=\"font-display font-bold text-gray-900 mb-5\">Contacts par service</h3>\n        <div class=\"space-y-4\">\n          <div class=\"flex items-center justify-between py-3 border-b border-slate-50\">\n            <div class=\"flex items-center gap-3\">\n              <div class=\"w-9 h-9 bg-primary-light rounded-lg flex items-center justify-center\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:18px\">school</span></div>\n              <div>\n                <div class=\"font-semibold text-gray-900 text-sm\">Scolarite</div>\n                <div class=\"text-xs text-slate-400\">scolarite@isi-suptech.ci</div>\n              </div>\n            </div>\n          </div>\n          <div class=\"flex items-center justify-between py-3 border-b border-slate-50\">\n            <div class=\"flex items-center gap-3\">\n              <div class=\"w-9 h-9 bg-primary-light rounded-lg flex items-center justify-center\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:18px\">edit_note</span></div>\n              <div>\n                <div class=\"font-semibold text-gray-900 text-sm\">Admissions</div>\n                <div class=\"text-xs text-slate-400\">admissions@isi-suptech.ci</div>\n              </div>\n            </div>\n          </div>\n          <div class=\"flex items-center justify-between py-3 border-b border-slate-50\">\n            <div class=\"flex items-center gap-3\">\n              <div class=\"w-9 h-9 bg-primary-light rounded-lg flex items-center justify-center\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:18px\">work</span></div>\n              <div>\n                <div class=\"font-semibold text-gray-900 text-sm\">Relations Entreprises</div>\n                <div class=\"text-xs text-slate-400\">entreprises@isi-suptech.ci</div>\n              </div>\n            </div>\n          </div>\n          <div class=\"flex items-center justify-between py-3\">\n            <div class=\"flex items-center gap-3\">\n              <div class=\"w-9 h-9 bg-primary-light rounded-lg flex items-center justify-center\"><span class=\"material-symbols-outlined text-primary\" style=\"font-size:18px\">payments</span></div>\n              <div>\n                <div class=\"font-semibold text-gray-900 text-sm\">Comptabilite / Frais</div>\n                <div class=\"text-xs text-slate-400\">finance@isi-suptech.ci</div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- Reseaux sociaux -->\n      <div class=\"bg-primary rounded-2xl p-6\">\n        <h3 class=\"font-display font-bold text-white mb-4\">Suivez-nous</h3>\n        <div class=\"grid grid-cols-2 gap-3\">\n          <a href=\"#\" class=\"bg-white/10 hover:bg-white/20 border border-white/15 rounded-xl p-3 flex items-center gap-3 transition-colors\">\n            <span class=\"material-symbols-outlined text-gold\" style=\"font-size:20px\">open_in_new</span>\n            <div><div class=\"text-white text-xs font-semibold\">Facebook</div><div class=\"text-white/50 text-xs\">@ISISuptech</div></div>\n          </a>\n          <a href=\"#\" class=\"bg-white/10 hover:bg-white/20 border border-white/15 rounded-xl p-3 flex items-center gap-3 transition-colors\">\n            <span class=\"material-symbols-outlined text-gold\" style=\"font-size:20px\">open_in_new</span>\n            <div><div class=\"text-white text-xs font-semibold\">LinkedIn</div><div class=\"text-white/50 text-xs\">ISI SUPTECH</div></div>\n          </a>\n          <a href=\"#\" class=\"bg-white/10 hover:bg-white/20 border border-white/15 rounded-xl p-3 flex items-center gap-3 transition-colors\">\n            <span class=\"material-symbols-outlined text-gold\" style=\"font-size:20px\">open_in_new</span>\n            <div><div class=\"text-white text-xs font-semibold\">YouTube</div><div class=\"text-white/50 text-xs\">ISI SUPTECH CI</div></div>\n          </a>\n          <a href=\"#\" class=\"bg-white/10 hover:bg-white/20 border border-white/15 rounded-xl p-3 flex items-center gap-3 transition-colors\">\n            <span class=\"material-symbols-outlined text-gold\" style=\"font-size:20px\">open_in_new</span>\n            <div><div class=\"text-white text-xs font-semibold\">WhatsApp</div><div class=\"text-white/50 text-xs\">+225 07 XX XX XX XX</div></div>\n          </a>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FAQ -->\n<section class=\"bg-white border-y border-slate-100 py-16\">\n  <div class=\"max-w-4xl mx-auto px-6\">\n    <div class=\"text-center mb-12\">\n      <div class=\"badge bg-primary-light text-primary mx-auto mb-4\">Questions frequentes</div>\n      <h2 class=\"font-display font-black text-4xl text-gray-900 mb-3\">FAQ</h2>\n      <p class=\"text-slate-500\">Les reponses aux questions les plus posees par nos futurs etudiants</p>\n    </div>\n\n    <!-- Categorie : Admissions -->\n    <h3 class=\"font-display font-bold text-lg text-gray-900 mb-4 flex items-center gap-2\">\n      <span class=\"w-1.5 h-6 bg-primary rounded-full\"></span>Admissions\n    </h3>\n    <div class=\"bg-surface rounded-2xl border border-slate-100 overflow-hidden mb-8\">\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Quel est le niveau requis pour entrer en Licence ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          Pour la Licence, le niveau requis est le Baccalaureat (toutes series scientifiques et techniques : C, D, E, F2, F3) avec mention au minimum Passable. Un test de logique et un entretien de motivation font partie du processus de selection.\n        </div>\n      </div>\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Acceptez-vous les candidats de terminale ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          Oui, les candidats de Terminale peuvent deposer un dossier de pre-inscription. L\'admission definitive est conditionnee par l\'obtention du Baccalaureat. Les candidats admis sous condition ont jusqu\'a fin septembre pour fournir leur attestation de reussite.\n        </div>\n      </div>\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Puis-je integrer directement en 2eme ou 3eme annee ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          Les integrations en cours de cursus (passerelle) sont possibles sur dossier. Elles sont soumises a une validation des acquis de l\'experience ou des etudes anterieures (VAE/VAP). Contactez le service des admissions avec votre dossier academique complet pour une etude personnalisee.\n        </div>\n      </div>\n    </div>\n\n    <!-- Categorie : Frais &amp; Financement -->\n    <h3 class=\"font-display font-bold text-lg text-gray-900 mb-4 flex items-center gap-2\">\n      <span class=\"w-1.5 h-6 bg-gold rounded-full\"></span>Frais &amp; Financement\n    </h3>\n    <div class=\"bg-surface rounded-2xl border border-slate-100 overflow-hidden mb-8\">\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Y a-t-il des facilites de paiement ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          Oui, les frais de scolarite peuvent etre regle en 3 tranches : 50% a l\'inscription (septembre), 30% en janvier, 20% en avril. Des facilites supplementaires peuvent etre accordees sur demande justifiee aupres du service financier.\n        </div>\n      </div>\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Des bourses sont-elles disponibles ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          ISI SUPTECH attribue chaque annee des bourses d\'excellence (reduction de 30 a 100% des frais) aux candidats ayant obtenu une mention Tres Bien ou Bien au Baccalaureat, et aux etudiants maintenant un rang dans le top 3 de leur promotion.\n        </div>\n      </div>\n    </div>\n\n    <!-- Categorie : Formations -->\n    <h3 class=\"font-display font-bold text-lg text-gray-900 mb-4 flex items-center gap-2\">\n      <span class=\"w-1.5 h-6 bg-primary-mid rounded-full\"></span>Formations &amp; Programmes\n    </h3>\n    <div class=\"bg-surface rounded-2xl border border-slate-100 overflow-hidden mb-8\">\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Les diplomes ISI sont-ils reconnus par l\'Etat ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          Oui, tous nos diplomes (BTS, Licence, Master) sont reconnus par le Ministere de l\'Enseignement Superieur et de la Recherche Scientifique de Cote d\'Ivoire. Nos formations sont accreditees dans le cadre du systeme LMD (Licence-Master-Doctorat).\n        </div>\n      </div>\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Les cours sont-ils dispenses en francais ou en anglais ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          L\'enseignement est principalement en francais. Des modules techniques sont dispenses en anglais, notamment les cours lies aux certifications internationales (Cisco, AWS). Un module d\'anglais technique est obligatoire en Licence.\n        </div>\n      </div>\n      <div class=\"faq-item\">\n        <button class=\"w-full text-left px-6 py-4 flex items-center justify-between font-semibold text-gray-900 text-sm hover:text-primary transition-colors\">\n          <span>Est-ce que les stages sont obligatoires ?</span>\n          <span class=\"material-symbols-outlined faq-icon text-slate-400\" style=\"font-size:20px\">expand_more</span>\n        </button>\n        <div class=\"faq-answer px-6 text-slate-600 text-sm leading-relaxed\">\n          Oui, un stage de 3 mois minimum est obligatoire en 3eme annee de Licence et en 2eme annee de Master. Notre service des relations entreprises accompagne les etudiants dans la recherche de stage aupres de notre reseau de 200+ entreprises partenaires.\n        </div>\n      </div>\n    </div>\n\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer class=\"bg-primary-dark text-white/60 py-12\">\n  <div class=\"max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-4 gap-8\">\n    <div class=\"md:col-span-2\">\n      <div class=\"flex items-center gap-3 mb-4\"><div class=\"w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white font-black text-sm\">IS</div><span class=\"font-display font-extrabold text-lg text-white\">ISI SUPTECH</span></div>\n      <p class=\"text-sm leading-relaxed\">Institut Superieur d\'Informatique et de Technologie. Former les experts numeriques du continent africain depuis 2003.</p>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Navigation</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li><a href=\"http://isi-suptech.local/\" class=\"hover:text-white transition-colors\">Accueil</a></li>\n        <li><a href=\"http://isi-suptech.local/formations/\" class=\"hover:text-white transition-colors\">Formations</a></li>\n        <li><a href=\"http://isi-suptech.local/admissions/\" class=\"hover:text-white transition-colors\">Admissions</a></li>\n        <li><a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"hover:text-white transition-colors\">Vie Etudiante</a></li>\n        <li><a href=\"http://isi-suptech.local/actualites/\" class=\"hover:text-white transition-colors\">Actualites</a></li>\n        <li><a href=\"http://isi-suptech.local/a-propos/\" class=\"hover:text-white transition-colors\">A Propos</a></li>\n        <li><a href=\"http://isi-suptech.local/contact/\" class=\"hover:text-white transition-colors\">Contact</a></li>\n      </ul>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Contact</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">location_on</span>Abidjan, Cocody - Cote d\'Ivoire</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">phone</span>+225 27 22 XX XX XX</li>\n        <li class=\"flex items-start gap-2\"><span class=\"material-symbols-outlined text-gold\" style=\"font-size:16px;margin-top:2px\">mail</span>contact@isi-suptech.ci</li>\n      </ul>\n    </div>\n  </div>\n  <div class=\"max-w-7xl mx-auto px-6 mt-8 pt-6 border-t border-white/10 text-center text-xs\">&copy; 2025 ISI SUPTECH. Tous droits reserves.</div>\n</footer>\n\n\nfunction toggleFaq(btn) {\n  const answer = btn.nextElementSibling;\n  const icon = btn.querySelector(\'.faq-icon\');\n  answer.classList.toggle(\'open\');\n  icon.classList.toggle(\'rotate\');\n}\n',	'Contact',	'',	'inherit',	'closed',	'closed',	'',	'47-revision-v1',	'',	'',	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'',	47,	'http://isi-suptech.local/?p=83',	0,	'revision',	'',	0),
(84,	0,	'2026-07-02 15:14:34',	'2026-07-02 15:14:34',	'<!-- HEADER -->\n<header class=\"bg-white/95 backdrop-blur-md sticky top-0 z-50 border-b border-slate-100 shadow-sm\">\n  <div class=\"max-w-7xl mx-auto px-6 h-20 flex items-center justify-between\">\n    <a href=\"http://isi-suptech.local/\" class=\"flex items-center gap-3 group flex-shrink-0\">\n      <div class=\"w-11 h-11 bg-primary rounded-xl flex items-center justify-center text-white font-black text-[15px] shadow-lg group-hover:bg-primary-mid transition-colors\">IS</div>\n      <div class=\"hidden sm:block\">\n        <div class=\"font-display font-extrabold text-xl text-primary tracking-tight leading-none\">ISI SUPTECH</div>\n        <div class=\"text-[10px] text-slate-400 font-semibold tracking-widest uppercase\">Institut Superieur d\'Informatique</div>\n      </div>\n    </a>\n    <nav class=\"hidden lg:flex items-center gap-8\">\n      <a href=\"http://isi-suptech.local/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Accueil</a>\n      <a href=\"http://isi-suptech.local/formations/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Formations</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Admissions</a>\n      <a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Vie Etudiante</a>\n      <a href=\"http://isi-suptech.local/a-propos/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">A Propos</a>\n      <a href=\"http://isi-suptech.local/contact/\" class=\"nav-link font-display font-medium text-sm text-slate-600 hover:text-primary\">Contact</a>\n    </nav>\n    <div class=\"flex items-center gap-3\">\n      <a href=\"#\" class=\"hidden md:inline text-sm font-semibold text-slate-500 hover:text-primary px-3\">Espace Etudiant</a>\n      <a href=\"http://isi-suptech.local/admissions/\" class=\"bg-primary hover:bg-primary-mid text-white px-5 py-2.5 rounded-lg text-sm font-bold shadow-md transition-all\">S\'inscrire</a>\n    </div>\n  </div>\n</header>\n\n<!-- HERO -->\n<section class=\"bg-primary-dark py-20 relative overflow-hidden\">\n  <div class=\"absolute inset-0 opacity-10\" style=\"background-image:radial-gradient(circle at 1px 1px,rgba(255,255,255,.4) 1px,transparent 0);background-size:32px 32px\"></div>\n  <div class=\"relative max-w-7xl mx-auto px-6\">\n    <div class=\"badge bg-gold/20 text-gold border border-gold/30 mb-5 anim-1\"><span class=\"material-symbols-outlined\" style=\"font-size:13px\">article</span>Blog &amp; Presse</div>\n    <h1 class=\"font-display font-black text-white text-5xl mb-4 anim-2\">Actualites ISI SUPTECH</h1>\n    <p class=\"text-white/70 text-lg max-w-xl anim-2\">Suivez l\'actualite de l\'Institut, les succes des etudiants, les partenariats et les evenements tech.</p>\n  </div>\n</section>\n\n<!-- CONTENU PRINCIPAL -->\n<div class=\"max-w-7xl mx-auto px-6 py-16\">\n  <div class=\"grid grid-cols-1 lg:grid-cols-3 gap-10\">\n\n    <!-- Articles -->\n    <div class=\"lg:col-span-2\">\n\n      <!-- Article a la une -->\n      <div class=\"card-lift bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm mb-8 group\">\n        <div class=\"img-zoom-wrap h-64\">\n          <img src=\"https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=800&amp;q=70\" class=\"w-full h-full object-cover\" alt=\"\">\n        </div>\n        <div class=\"p-7\">\n          <div class=\"flex items-center gap-3 mb-3\">\n            <span class=\"badge bg-gold text-gray-900\">A la une</span>\n            <span class=\"badge bg-primary-light text-primary\">Evenement</span>\n            <span class=\"text-slate-400 text-xs\">15 Avril 2025</span>\n          </div>\n          <h2 class=\"font-display font-black text-2xl text-gray-900 mb-3 group-hover:text-primary transition-colors\">ISI SUPTECH remporte le 1er prix du Hackathon Numerique d\'Abidjan 2025</h2>\n          <p class=\"text-slate-500 leading-relaxed mb-5\">L\'equipe \"CodeForest\" composee de 5 etudiants du Master RESI a remporte le premier prix (1 million FCFA) du hackathon organise par le Ministere de la Transition Numerique. Leur projet : une plateforme IA de detection precoce des maladies agricoles via drone et vision par ordinateur.</p>\n          <a href=\"#\" class=\"inline-flex items-center gap-1 text-primary font-semibold text-sm hover:gap-2 transition-all\">Lire l\'article complet <span class=\"material-symbols-outlined\" style=\"font-size:16px\">arrow_forward</span></a>\n        </div>\n      </div>\n\n      <!-- Grille articles secondaires -->\n      <div class=\"grid grid-cols-1 md:grid-cols-2 gap-6 mb-8\">\n\n        <a href=\"#\" class=\"card-lift bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm group flex flex-col\">\n          <div class=\"img-zoom-wrap h-40\">\n            <img src=\"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=500&amp;q=70\" class=\"w-full h-full object-cover\" alt=\"\">\n          </div>\n          <div class=\"p-5 flex-1 flex flex-col\">\n            <div class=\"flex items-center gap-2 mb-2\">\n              <span class=\"badge bg-primary-light text-primary\">Partenariat</span>\n              <span class=\"text-slate-400 text-xs\">10 Avril 2025</span>\n            </div>\n            <h3 class=\"font-display font-bold text-gray-900 text-base mb-2 group-hover:text-primary transition-colors flex-1\">Nouveau partenariat avec Cisco Networking Academy</h3>\n            <p class=\"text-slate-500 text-sm\">ISI SUPTECH devient Cisco Academy officielle, permettant aux etudiants de passer leurs certifications CCNA/CCNP directement sur le campus.</p>\n          </div>\n        </a>\n\n        <a href=\"#\" class=\"card-lift bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm group flex flex-col\">\n          <div class=\"img-zoom-wrap h-40\">\n            <img src=\"https://images.unsplash.com/photo-1517245386807-bb43f82c33c4?w=500&amp;q=70\" class=\"w-full h-full object-cover\" alt=\"\">\n          </div>\n          <div class=\"p-5 flex-1 flex flex-col\">\n            <div class=\"flex items-center gap-2 mb-2\">\n              <span class=\"badge bg-green-100 text-green-700\">Insertion pro</span>\n              <span class=\"text-slate-400 text-xs\">3 Avril 2025</span>\n            </div>\n            <h3 class=\"font-display font-bold text-gray-900 text-base mb-2 group-hover:text-primary transition-colors flex-1\">Promo 2024 : 97% des laureats employes en moins de 4 mois</h3>\n            <p class=\"text-slate-500 text-sm\">Un record historique pour l\'ISI SUPTECH. La promotion 2024 affiche le meilleur taux d\'insertion depuis la creation de l\'etablissement.</p>\n          </div>\n        </a>\n\n        <a href=\"#\" class=\"card-lift bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm group flex flex-col\">\n          <div class=\"img-zoom-wrap h-40\">\n            <img src=\"https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=500&amp;q=70\" class=\"w-full h-full object-cover\" alt=\"\">\n          </div>\n          <div class=\"p-5 flex-1 flex flex-col\">\n            <div class=\"flex items-center gap-2 mb-2\">\n              <span class=\"badge bg-purple-100 text-purple-700\">IA &amp; Innovation</span>\n              <span class=\"text-slate-400 text-xs\">28 Mars 2025</span>\n            </div>\n            <h3 class=\"font-display font-bold text-gray-900 text-base mb-2 group-hover:text-primary transition-colors flex-1\">Ouverture du laboratoire d\'Intelligence Artificielle</h3>\n            <p class=\"text-slate-500 text-sm\">Un nouveau labo IA equipe de stations GPU A100 (Nvidia) est desormais accessible aux etudiants de Master pour leurs projets de deep learning.</p>\n          </div>\n        </a>\n\n        <a href=\"#\" class=\"card-lift bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm group flex flex-col\">\n          <div class=\"img-zoom-wrap h-40\">\n            <img src=\"https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=500&amp;q=70\" class=\"w-full h-full object-cover\" alt=\"\">\n          </div>\n          <div class=\"p-5 flex-1 flex flex-col\">\n            <div class=\"flex items-center gap-2 mb-2\">\n              <span class=\"badge bg-orange-100 text-orange-700\">Conference</span>\n              <span class=\"text-slate-400 text-xs\">20 Mars 2025</span>\n            </div>\n            <h3 class=\"font-display font-bold text-gray-900 text-base mb-2 group-hover:text-primary transition-colors flex-1\">ISI Tech Summit 2025 : 500 participants, 20 intervenants</h3>\n            <p class=\"text-slate-500 text-sm\">La 3eme edition de l\'ISI Tech Summit a reuni les acteurs du numerique d\'Afrique de l\'Ouest. Replay disponible sur notre chaine YouTube.</p>\n          </div>\n        </a>\n\n      </div>\n\n      <!-- Pagination -->\n      <div class=\"flex items-center gap-2 justify-center\">\n        <button class=\"w-9 h-9 rounded-lg bg-primary text-white text-sm font-bold\">1</button>\n        <button class=\"w-9 h-9 rounded-lg bg-white border border-slate-200 text-slate-600 text-sm hover:border-primary hover:text-primary transition-colors\">2</button>\n        <button class=\"w-9 h-9 rounded-lg bg-white border border-slate-200 text-slate-600 text-sm hover:border-primary hover:text-primary transition-colors\">3</button>\n        <span class=\"text-slate-400 px-1\">...</span>\n        <button class=\"w-9 h-9 rounded-lg bg-white border border-slate-200 text-slate-600 text-sm hover:border-primary hover:text-primary transition-colors\">8</button>\n      </div>\n    </div>\n\n    <!-- Sidebar -->\n    <aside class=\"space-y-7\">\n\n      <!-- Recherche -->\n      <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-5\">\n        <h4 class=\"font-display font-bold text-gray-900 text-sm mb-3\">Rechercher</h4>\n        <div class=\"relative\">\n          \n          <span class=\"material-symbols-outlined absolute right-3 top-1/2 -translate-y-1/2 text-slate-400\" style=\"font-size:18px\">search</span>\n        </div>\n      </div>\n\n      <!-- Categories -->\n      <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-5\">\n        <h4 class=\"font-display font-bold text-gray-900 text-sm mb-4\">Categories</h4>\n        <ul class=\"space-y-2\">\n          <li class=\"flex items-center justify-between text-sm py-2 border-b border-slate-50\">\n            <a href=\"#\" class=\"text-slate-600 hover:text-primary transition-colors\">Evenements</a>\n            <span class=\"badge bg-primary-light text-primary\">12</span>\n          </li>\n          <li class=\"flex items-center justify-between text-sm py-2 border-b border-slate-50\">\n            <a href=\"#\" class=\"text-slate-600 hover:text-primary transition-colors\">Partenariats</a>\n            <span class=\"badge bg-primary-light text-primary\">8</span>\n          </li>\n          <li class=\"flex items-center justify-between text-sm py-2 border-b border-slate-50\">\n            <a href=\"#\" class=\"text-slate-600 hover:text-primary transition-colors\">Insertion pro</a>\n            <span class=\"badge bg-primary-light text-primary\">15</span>\n          </li>\n          <li class=\"flex items-center justify-between text-sm py-2 border-b border-slate-50\">\n            <a href=\"#\" class=\"text-slate-600 hover:text-primary transition-colors\">Innovation &amp; IA</a>\n            <span class=\"badge bg-primary-light text-primary\">6</span>\n          </li>\n          <li class=\"flex items-center justify-between text-sm py-2\">\n            <a href=\"#\" class=\"text-slate-600 hover:text-primary transition-colors\">Vie etudiante</a>\n            <span class=\"badge bg-primary-light text-primary\">10</span>\n          </li>\n        </ul>\n      </div>\n\n      <!-- Articles recents -->\n      <div class=\"bg-white rounded-2xl border border-slate-100 shadow-sm p-5\">\n        <h4 class=\"font-display font-bold text-gray-900 text-sm mb-4\">Articles recents</h4>\n        <ul class=\"space-y-4\">\n          <li class=\"flex gap-3\">\n            <img src=\"https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=120&amp;q=60\" class=\"w-14 h-14 rounded-lg object-cover flex-shrink-0\" alt=\"\">\n            <div><a href=\"#\" class=\"text-sm font-semibold text-gray-900 hover:text-primary transition-colors leading-tight block mb-1\">ISI remporte le Hackathon 2025</a><div class=\"text-xs text-slate-400\">15 Avril 2025</div></div>\n          </li>\n          <li class=\"flex gap-3\">\n            <img src=\"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=120&amp;q=60\" class=\"w-14 h-14 rounded-lg object-cover flex-shrink-0\" alt=\"\">\n            <div><a href=\"#\" class=\"text-sm font-semibold text-gray-900 hover:text-primary transition-colors leading-tight block mb-1\">Partenariat Cisco Academy officialise</a><div class=\"text-xs text-slate-400\">10 Avril 2025</div></div>\n          </li>\n          <li class=\"flex gap-3\">\n            <img src=\"https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=120&amp;q=60\" class=\"w-14 h-14 rounded-lg object-cover flex-shrink-0\" alt=\"\">\n            <div><a href=\"#\" class=\"text-sm font-semibold text-gray-900 hover:text-primary transition-colors leading-tight block mb-1\">Ouverture du labo Intelligence Artificielle</a><div class=\"text-xs text-slate-400\">28 Mars 2025</div></div>\n          </li>\n        </ul>\n      </div>\n\n      <!-- Newsletter -->\n      <div class=\"bg-primary rounded-2xl p-6\">\n        <h4 class=\"font-display font-bold text-white text-base mb-2\">Newsletter ISI</h4>\n        <p class=\"text-white/60 text-sm mb-4\">Recevez les actualites directement dans votre boite mail.</p>\n        \n        <button class=\"w-full bg-gold hover:bg-yellow-400 text-gray-900 py-2.5 rounded-xl font-bold text-sm transition-colors\">S\'abonner</button>\n      </div>\n\n    </aside>\n  </div>\n</div>\n\n<!-- FOOTER -->\n<footer class=\"bg-primary-dark text-white/60 py-12\">\n  <div class=\"max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-4 gap-8\">\n    <div class=\"md:col-span-2\">\n      <div class=\"flex items-center gap-3 mb-4\"><div class=\"w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white font-black text-sm\">IS</div><span class=\"font-display font-extrabold text-lg text-white\">ISI SUPTECH</span></div>\n      <p class=\"text-sm leading-relaxed\">Institut Superieur d\'Informatique et de Technologie. Former les experts numeriques du continent africain depuis 2003.</p>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Navigation</h4>\n      <ul class=\"space-y-2 text-sm\">\n        <li><a href=\"http://isi-suptech.local/\" class=\"hover:text-white transition-colors\">Accueil</a></li>\n        <li><a href=\"http://isi-suptech.local/formations/\" class=\"hover:text-white transition-colors\">Formations</a></li>\n        <li><a href=\"http://isi-suptech.local/admissions/\" class=\"hover:text-white transition-colors\">Admissions</a></li>\n        <li><a href=\"http://isi-suptech.local/vie-etudiante/\" class=\"hover:text-white transition-colors\">Vie Etudiante</a></li>\n        <li><a href=\"http://isi-suptech.local/actualites/\" class=\"hover:text-white transition-colors\">Actualites</a></li>\n        <li><a href=\"http://isi-suptech.local/a-propos/\" class=\"hover:text-white transition-colors\">A Propos</a></li>\n        <li><a href=\"http://isi-suptech.local/contact/\" class=\"hover:text-white transition-colors\">Contact</a></li>\n      </ul>\n    </div>\n    <div>\n      <h4 class=\"font-display font-bold text-white text-sm mb-4\">Contact</h4>\n      <ul class